export async function GET() {
    // Return current services grouped by VPS
    const services = await prisma.service.findMany({
        include: {
            vps: { select: { id: true, name: true, ipAddress: true } },
        },
        orderBy: { createdAt: "desc" },
    });

    const byVps = services.reduce((acc: any, svc) => {
        const vpsKey = svc.vps?.ipAddress || "unassigned";
        if (!acc[vpsKey]) acc[vpsKey] = [];
        acc[vpsKey].push(svc);
        return acc;
    }, {});

    return NextResponse.json({ success: true, data: services, byVps, count: services.length });
}

export async function POST() {
    const results = {
        created: 0,
        skipped: 0,
        errors: [] as string[],
        vpsNotFound: [] as string[],
    };

    for (const dns of DNS_SERVICES) {
        try {
            // Find VPS by IP
            const vps = await prisma.vPS.findFirst({
                where: { ipAddress: dns.ip },
            });

            if (!vps) {
                if (!results.vpsNotFound.includes(dns.ip)) {
                    results.vpsNotFound.push(dns.ip);
                }
                continue;
            }

            // Check if service already exists
            const existing = await prisma.service.findFirst({
                where: {
                    name: dns.subdomain,
                    vpsId: vps.id,
                },
            });

            if (existing) {
                results.skipped++;
                continue;
            }

            // Create service
            await prisma.service.create({
                data: {
                    name: dns.subdomain,
                    type: dns.type,
                    url: `https://${dns.subdomain}.renace.tech`,
                    vpsId: vps.id,
                    status: "running",
                },
            });

            results.created++;
        } catch (error: any) {
            results.errors.push(`${dns.subdomain}: ${error.message}`);
        }
    }

    return NextResponse.json({
        success: true,
        message: `Created ${results.created} services, skipped ${results.skipped} existing`,
        ...results,
    });
}

import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/prisma";

// GET - Get all settings or by category
export async function GET(request: NextRequest) {
    try {
        const url = new URL(request.url);
        const category = url.searchParams.get("category");
        const key = url.searchParams.get("key");

        if (key) {
            const setting = await prisma.appSettings.findUnique({
                where: { key },
            });
            return NextResponse.json({
                success: true,
                data: setting?.value || null
            });
        }

        const settings = await prisma.appSettings.findMany({
            where: category ? { category } : undefined,
            orderBy: { key: "asc" },
        });

        // Convert to key-value object
        const settingsMap = settings.reduce((acc, s) => {
            acc[s.key] = s.value;
            return acc;
        }, {} as Record<string, string>);

        return NextResponse.json({ success: true, data: settingsMap });
    } catch (error) {
        console.error("Settings GET Error:", error);
        return NextResponse.json(
            { success: false, error: "Error obteniendo configuración" },
            { status: 500 }
        );
    }
}

// POST - Save settings
export async function POST(request: NextRequest) {
    try {
        const body = await request.json();
        const { settings } = body; // { key: value, key2: value2, ... }

        if (!settings || typeof settings !== "object") {
            return NextResponse.json(
                { success: false, error: "Settings object required" },
                { status: 400 }
            );
        }

        const results = [];
        for (const [key, value] of Object.entries(settings)) {
            const category = key.split("_")[0]; // e.g., smtp_host -> smtp

            const result = await prisma.appSettings.upsert({
                where: { key },
                create: {
                    key,
                    value: String(value),
                    category,
                },
                update: {
                    value: String(value),
                },
            });
            results.push(result);
        }

        return NextResponse.json({ success: true, data: results });
    } catch (error) {
        console.error("Settings POST Error:", error);
        return NextResponse.json(
            { success: false, error: "Error guardando configuración" },
            { status: 500 }
        );
    }
}

// DELETE - Delete a setting
export async function DELETE(request: NextRequest) {
    try {
        const url = new URL(request.url);
        const key = url.searchParams.get("key");

        if (!key) {
            return NextResponse.json(
                { success: false, error: "Key required" },
                { status: 400 }
            );
        }

        await prisma.appSettings.delete({
            where: { key },
        });

        return NextResponse.json({ success: true });
    } catch (error) {
        return NextResponse.json(
            { success: false, error: "Error eliminando configuración" },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export const dynamic = 'force-dynamic';

export async function GET(request: NextRequest) {
    try {
        const clients = await prisma.client.findMany();
        const vps = await prisma.vps.findMany();
        const services = await prisma.service.findMany();
        const payments = await prisma.payment.findMany();
        const revenueHistory = await prisma.revenueHistory.findMany();
        const appSettings = await prisma.appSettings.findMany();

        const backupData = {
            version: "1.0",
            timestamp: new Date().toISOString(),
            data: {
                clients,
                vps,
                services,
                payments,
                revenueHistory,
                appSettings
            }
        };

        return NextResponse.json(backupData);
    } catch (error: any) {
        console.error("Export error:", error);
        return NextResponse.json(
            { error: "Failed to export data", details: error.message },
            { status: 500 }
        );
    }
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
