                            </table>
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* Generate Invoice Modal */}
            <Dialog open={!!selectedClient} onOpenChange={() => setSelectedClient(null)}>
                <DialogContent className="max-w-md">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
