                        </Button>
                        <Button
                            onClick={handleGenerateInvoice}
                            disabled={isGenerating}
                            className="rounded-xl bg-gradient-to-r from-violet-500 to-purple-600"
                        >
                            {isGenerating ? (
                                <>
