                                    Generar Factura
                                </>
                            )}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import {
    Users, ArrowLeft, Edit, Save, X, Mail, Phone, Building, DollarSign,
    Calendar, Server, Database, FileText, ExternalLink, Trash2, RefreshCw, Receipt
} from "lucide-react";
import { motion } from "framer-motion";
import { useToast } from "@/components/ui/toast";

interface ClientDetail {
    id: string;
    name: string;
    email: string | null;
    phone: string | null;
    companyName: string | null;
    notes: string | null;
    monthlyFee: number;
    paymentDay: number;
    isActive: boolean;
    currency: string;
    odooPartnerId: number | null;
    vpsList: Array<{ id: string; name: string; ipAddress: string; status: string; monthlyCost: number }>;
    services: Array<{ id: string; name: string; type: string; url: string | null; monthlyCost: number; status: string }>;
    payments: Array<{ id: string; amount: number; date: string; status: string; odooInvoiceName: string | null }>;
    vpsCost: number;
    serviceCost: number;
    totalMonthlyCost: number;
}

export default function ClientDetailPage() {
    const params = useParams();
    const router = useRouter();
    const clientId = params.id as string;

    const [client, setClient] = useState<ClientDetail | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isEditing, setIsEditing] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const { addToast } = useToast();

    const [formData, setFormData] = useState({
        name: "",
        email: "",
        phone: "",
        companyName: "",
        notes: "",
        monthlyFee: "",
        paymentDay: "",
        isActive: true,
    });

    useEffect(() => {
        fetchClient();
    }, [clientId]);

    const fetchClient = async () => {
        setIsLoading(true);
        try {
            const response = await fetch(`/api/clients/${clientId}`);
            const data = await response.json();
            if (data.success) {
                setClient(data.data);
                setFormData({
                    name: data.data.name || "",
                    email: data.data.email || "",
                    phone: data.data.phone || "",
                    companyName: data.data.companyName || "",
                    notes: data.data.notes || "",
                    monthlyFee: String(data.data.monthlyFee || 0),
                    paymentDay: String(data.data.paymentDay || 1),
                    isActive: data.data.isActive,
                });
            } else {
                addToast("Error al cargar cliente", "error");
            }
        } catch (error) {
            addToast("Error de conexión", "error");
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async () => {
        setIsSaving(true);
        try {
            const response = await fetch(`/api/clients/${clientId}`, {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    name: formData.name,
                    email: formData.email || null,
                    phone: formData.phone || null,
                    companyName: formData.companyName || null,
                    notes: formData.notes || null,
                    monthlyFee: parseFloat(formData.monthlyFee) || 0,
                    paymentDay: parseInt(formData.paymentDay) || 1,
                    isActive: formData.isActive,
                }),
            });

            const data = await response.json();
            if (data.success) {
                addToast("Cliente actualizado exitosamente", "success");
                setIsEditing(false);
                fetchClient();
            } else {
                addToast(data.error || "Error al guardar", "error");
            }
        } catch (error) {
            addToast("Error de conexión", "error");
        } finally {
            setIsSaving(false);
        }
    };

    const handleDelete = async () => {
        if (!confirm("¿Estás seguro de eliminar este cliente?")) return;

        try {
            const response = await fetch(`/api/clients/${clientId}`, { method: "DELETE" });
            const data = await response.json();
            if (data.success) {
                addToast("Cliente eliminado", "success");
                router.push("/clients");
            } else {
                addToast(data.error || "Error al eliminar", "error");
            }
        } catch (error) {
            addToast("Error de conexión", "error");
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center py-20">
                <RefreshCw className="w-8 h-8 text-violet-500 animate-spin" />
            </div>
        );
    }

    if (!client) {
        return (
            <div className="text-center py-20">
                <Users className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                <h2 className="text-xl font-bold text-gray-700">Cliente no encontrado</h2>
                <Link href="/clients">
                    <Button className="mt-4">Volver a Clientes</Button>
                </Link>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <Link href="/clients">
                        <Button variant="ghost" size="icon" className="rounded-full">
                            <ArrowLeft size={20} />
                        </Button>
                    </Link>
                    <div>
                        <div className="flex items-center gap-3">
                            <h2 className="text-3xl font-bold tracking-tight">{client.name}</h2>
                            <Badge variant={client.isActive ? "success" : "warning"} className="rounded-full">
                                {client.isActive ? "Activo" : "Inactivo"}
                            </Badge>
                        </div>
                        <p className="text-muted-foreground">{client.companyName || "Sin empresa"}</p>
                    </div>
                </div>
                <div className="flex gap-2">
                    {isEditing ? (
                        <>
                            <Button variant="outline" onClick={() => setIsEditing(false)}>
                                <X size={16} className="mr-2" /> Cancelar
                            </Button>
                            <Button onClick={handleSave} disabled={isSaving} className="bg-green-500 hover:bg-green-600">
                                <Save size={16} className="mr-2" /> {isSaving ? "Guardando..." : "Guardar"}
                            </Button>
                        </>
                    ) : (
                        <>
                            <Button variant="outline" onClick={() => setIsEditing(true)}>
                                <Edit size={16} className="mr-2" /> Editar
                            </Button>
                            <Button variant="destructive" onClick={handleDelete}>
                                <Trash2 size={16} className="mr-2" /> Eliminar
                            </Button>
                        </>
                    )}
                </div>
            </div>

            {/* Stats Cards */}
            <div className="grid gap-4 md:grid-cols-4">
                <Card className="bg-gradient-to-br from-violet-500 to-purple-600 text-white rounded-2xl border-0 shadow-lg">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <DollarSign className="h-8 w-8 opacity-80" />
                            <div>
                                <p className="text-sm opacity-80">Costo Total Mensual</p>
                                <p className="text-2xl font-bold">${client.totalMonthlyCost.toFixed(2)}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <Server className="h-6 w-6 text-blue-500" />
                            <div>
                                <p className="text-sm text-muted-foreground">VPS</p>
                                <p className="text-2xl font-bold">{client.vpsList.length}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <Database className="h-6 w-6 text-purple-500" />
                            <div>
                                <p className="text-sm text-muted-foreground">Servicios</p>
                                <p className="text-2xl font-bold">{client.services.length}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <Calendar className="h-6 w-6 text-green-500" />
                            <div>
                                <p className="text-sm text-muted-foreground">Día de Pago</p>
                                <p className="text-2xl font-bold">{client.paymentDay}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
            </div>

            <div className="grid gap-6 md:grid-cols-2">
                {/* Client Info Form */}
                <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Users className="w-5 h-5 text-violet-500" />
                            Información del Cliente
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Nombre</label>
                                {isEditing ? (
                                    <Input
                                        value={formData.name}
                                        onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                        className="rounded-xl border-2"
                                    />
                                ) : (
                                    <p className="font-semibold">{client.name}</p>
                                )}
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1"><Building size={14} /> Empresa</label>
                                {isEditing ? (
                                    <Input
                                        value={formData.companyName}
                                        onChange={(e) => setFormData({ ...formData, companyName: e.target.value })}
                                        className="rounded-xl border-2"
                                    />
                                ) : (
                                    <p className="text-muted-foreground">{client.companyName || "-"}</p>
                                )}
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1"><Mail size={14} /> Email</label>
                                {isEditing ? (
                                    <Input
                                        value={formData.email}
                                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                        className="rounded-xl border-2"
                                    />
                                ) : (
                                    <p className="text-muted-foreground">{client.email || "-"}</p>
                                )}
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1"><Phone size={14} /> Teléfono</label>
                                {isEditing ? (
                                    <Input
                                        value={formData.phone}
                                        onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                                        className="rounded-xl border-2"
                                    />
                                ) : (
                                    <p className="text-muted-foreground">{client.phone || "-"}</p>
                                )}
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1"><DollarSign size={14} /> Tarifa Base</label>
                                {isEditing ? (
                                    <Input
                                        type="number"
                                        value={formData.monthlyFee}
                                        onChange={(e) => setFormData({ ...formData, monthlyFee: e.target.value })}
                                        className="rounded-xl border-2"
                                    />
                                ) : (
                                    <p className="font-semibold">${client.monthlyFee}/mes</p>
                                )}
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1"><Calendar size={14} /> Día de Pago</label>
                                {isEditing ? (
                                    <Input
                                        type="number"
                                        min="1"
                                        max="31"
                                        value={formData.paymentDay}
                                        onChange={(e) => setFormData({ ...formData, paymentDay: e.target.value })}
                                        className="rounded-xl border-2"
                                    />
                                ) : (
                                    <p>{client.paymentDay}</p>
                                )}
                            </div>
                        </div>
                        {isEditing && (
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1"><FileText size={14} /> Notas</label>
                                <textarea
                                    value={formData.notes}
                                    onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                                    rows={3}
                                    className="w-full px-3 py-2 rounded-xl border-2 border-gray-200 focus:border-violet-300 focus:outline-none resize-none"
                                />
                            </div>
                        )}
                    </CardContent>
                </Card>

                {/* VPS & Services */}
                <div className="space-y-6">
                    {/* VPS List */}
                    <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Server className="w-5 h-5 text-blue-500" />
                                VPS Asignados ({client.vpsList.length})
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            {client.vpsList.length === 0 ? (
                                <p className="text-muted-foreground text-center py-4">Sin VPS asignados</p>
                            ) : (
                                <div className="space-y-2">
                                    {client.vpsList.map((vps) => (
                                        <Link key={vps.id} href={`/vps/${vps.id}`}>
                                            <div className="flex items-center justify-between p-3 rounded-xl bg-gray-50 hover:bg-blue-50 transition-colors cursor-pointer">
                                                <div>
                                                    <p className="font-medium">{vps.name}</p>
                                                    <p className="text-sm text-muted-foreground">{vps.ipAddress}</p>
                                                </div>
                                                <div className="text-right">
                                                    <Badge variant={vps.status === "running" ? "success" : "warning"}>{vps.status}</Badge>
                                                    <p className="text-sm font-medium mt-1">${vps.monthlyCost}/mes</p>
                                                </div>
                                            </div>
                                        </Link>
                                    ))}
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    {/* Services List */}
                    <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Database className="w-5 h-5 text-purple-500" />
                                Servicios ({client.services.length})
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            {client.services.length === 0 ? (
                                <p className="text-muted-foreground text-center py-4">Sin servicios</p>
                            ) : (
                                <div className="space-y-2">
                                    {client.services.map((service) => (
                                        <div key={service.id} className="flex items-center justify-between p-3 rounded-xl bg-gray-50 hover:bg-purple-50 transition-colors">
                                            <div className="flex items-center gap-3">
                                                <Link href={`/services/${service.id}`} className="font-medium hover:text-violet-600">
                                                    {service.name}
                                                </Link>
                                                <Badge variant="outline">{service.type}</Badge>
                                                {service.url && (
                                                    <a href={service.url} target="_blank" rel="noopener noreferrer" className="text-cyan-500 hover:text-cyan-600">
                                                        <ExternalLink size={14} />
                                                    </a>
                                                )}
                                            </div>
                                            <div className="text-right">
                                                <p className="text-sm font-medium">${service.monthlyCost}/mes</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>

            {/* Payment History */}
            <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Receipt className="w-5 h-5 text-green-500" />
                        Historial de Pagos ({client.payments.length})
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    {client.payments.length === 0 ? (
                        <p className="text-muted-foreground text-center py-8">Sin pagos registrados</p>
                    ) : (
                        <div className="overflow-x-auto">
                            <table className="w-full">
                                <thead>
                                    <tr className="border-b border-gray-200">
                                        <th className="text-left py-3 px-4 font-medium text-gray-500">Fecha</th>
                                        <th className="text-left py-3 px-4 font-medium text-gray-500">Factura</th>
                                        <th className="text-right py-3 px-4 font-medium text-gray-500">Monto</th>
                                        <th className="text-center py-3 px-4 font-medium text-gray-500">Estado</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {client.payments.map((payment, index) => (
                                        <motion.tr
                                            key={payment.id}
                                            initial={{ opacity: 0, y: 10 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            transition={{ delay: index * 0.05 }}
                                            className="border-b border-gray-100 hover:bg-green-50/50 transition-colors"
                                        >
                                            <td className="py-3 px-4">
                                                {new Date(payment.date).toLocaleDateString('es-DO', {
                                                    year: 'numeric',
                                                    month: 'short',
                                                    day: 'numeric'
                                                })}
                                            </td>
                                            <td className="py-3 px-4">
                                                {payment.odooInvoiceName ? (
                                                    <span className="font-mono text-sm text-violet-600">{payment.odooInvoiceName}</span>
                                                ) : (
                                                    <span className="text-gray-400">-</span>
                                                )}
                                            </td>
                                            <td className="py-3 px-4 text-right font-bold text-green-600">
                                                ${payment.amount.toFixed(2)}
                                            </td>
                                            <td className="py-3 px-4 text-center">
                                                <Badge
                                                    variant={
                                                        payment.status === 'completed' ? 'success' :
                                                            payment.status === 'pending' ? 'warning' :
                                                                payment.status === 'cancelled' ? 'destructive' : 'outline'
                                                    }
                                                    className="rounded-full"
                                                >
                                                    {payment.status === 'completed' ? 'Pagado' :
                                                        payment.status === 'pending' ? 'Pendiente' :
                                                            payment.status === 'cancelled' ? 'Cancelado' : payment.status}
                                                </Badge>
                                            </td>
                                        </motion.tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Users, Plus, Search, Mail, Phone, Calendar, DollarSign, AlertTriangle, RefreshCw, Building, FileText } from "lucide-react";
import { motion } from "framer-motion";
import { useToast } from "@/components/ui/toast";

export default function ClientsPage() {
    const [clients, setClients] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const { addToast } = useToast();

    // Form state
    const [formData, setFormData] = useState({
        name: "",
        email: "",
        phone: "",
        companyName: "",
        notes: "",
        monthlyFee: "",
        paymentDay: "1",
    });

    const fetchClients = () => {
        setIsLoading(true);
        fetch("/api/clients")
            .then(res => res.json())
            .then(response => {
                // Handle both { success: true, data: [...] } and array format
                const data = response.data || response;
                setClients(Array.isArray(data) ? data : []);
                setIsLoading(false);
            })
            .catch(err => {
                console.error("Error fetching clients:", err);
                setIsLoading(false);
            });
    };

    useEffect(() => {
        fetchClients();
    }, []);

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name.trim()) {
            addToast("El nombre es requerido", "error");
            return;
        }

        setIsSubmitting(true);
        try {
            const response = await fetch("/api/clients", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    name: formData.name,
                    email: formData.email || null,
                    phone: formData.phone || null,
                    companyName: formData.companyName || null,
                    notes: formData.notes || null,
                    monthlyFee: parseFloat(formData.monthlyFee) || 0,
                    paymentDay: parseInt(formData.paymentDay) || 1,
                }),
            });

            if (response.ok) {
                addToast("Cliente creado exitosamente", "success");
                setIsModalOpen(false);
                setFormData({ name: "", email: "", phone: "", companyName: "", notes: "", monthlyFee: "", paymentDay: "1" });
                fetchClients();
            } else {
                const error = await response.json();
                addToast(error.error || "Error al crear cliente", "error");
            }
        } catch (error) {
            addToast("Error de conexión", "error");
        } finally {
            setIsSubmitting(false);
        }
    };

    const filteredClients = clients.filter(c =>
        c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.email?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const totalRevenue = clients.reduce((sum, c) => sum + (c.monthlyFee || 0), 0);
    const overdueClients = clients.filter(c => {
        if (!c.paymentDay) return false;
        const today = new Date().getDate();
        return today > c.paymentDay;
    });

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight">Clientes</h2>
                    <p className="text-muted-foreground">Gestiona tus cuentas de clientes y pagos</p>
                </div>
                <Button
                    onClick={() => setIsModalOpen(true)}
                    className="gap-2 bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 shadow-lg shadow-purple-200"
                >
                    <Plus size={16} />
                    Agregar Cliente
                </Button>
            </div>

            {/* Stats Summary */}
            <div className="grid gap-4 md:grid-cols-4">
                <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-primary/20">
                                <Users className="h-5 w-5 text-primary" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Total Clientes</p>
                                <p className="text-2xl font-bold">{clients.length}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-green-500/20">
                                <DollarSign className="h-5 w-5 text-green-400" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Ingresos Mensuales</p>
                                <p className="text-2xl font-bold">${totalRevenue.toLocaleString()}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-blue-500/20">
                                <Calendar className="h-5 w-5 text-blue-400" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Pendientes Pago</p>
                                <p className="text-2xl font-bold">{clients.length - overdueClients.length}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-red-100 shadow-sm shadow-red-50">
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-red-500/20">
                                <AlertTriangle className="h-5 w-5 text-red-400" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Vencidos</p>
                                <p className="text-2xl font-bold text-red-400">{overdueClients.length}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Search */}
            <div className="flex gap-4">
                <div className="relative flex-1 max-w-sm">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder="Buscar clientes..."
                        className="pl-9 rounded-xl border-2"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
                <Button variant="outline" className="rounded-xl border-2">Todos los Estados</Button>
            </div>

            {/* Clients List */}
            <div className="space-y-3">
                {isLoading ? (
                    <div className="flex justify-center py-12">
                        <RefreshCw className="w-8 h-8 text-violet-500 animate-spin" />
                    </div>
                ) : filteredClients.length === 0 ? (
                    <Card className="bg-white/50 border-dashed border-2 p-12 text-center rounded-2xl">
                        <div className="flex flex-col items-center gap-2">
                            <Users className="w-12 h-12 text-gray-300" />
                            <h3 className="text-lg font-bold text-gray-700">No hay clientes</h3>
                            <p className="text-gray-500">Agrega tu primer cliente para comenzar la gestión.</p>
                            <Button
                                onClick={() => setIsModalOpen(true)}
                                className="mt-4 gap-2"
                            >
                                <Plus size={16} />
                                Agregar Cliente
                            </Button>
                        </div>
                    </Card>
                ) : (
                    filteredClients.map((client, index) => (
                        <motion.div
                            key={client.id}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: index * 0.05 }}
                        >
                            <Card className="bg-white/70 backdrop-blur hover:bg-white transition-all border-2 border-gray-100 rounded-2xl group">
                                <CardContent className="py-4">
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-4">
                                            <div className="w-12 h-12 rounded-full bg-gradient-to-br from-violet-500 to-purple-600 flex items-center justify-center text-white font-bold text-lg shadow-md">
                                                {client.name.charAt(0)}
                                            </div>
                                            <div>
                                                <div className="flex items-center gap-2">
                                                    <h3 className="font-semibold">{client.name}</h3>
                                                    <Badge variant={client.isActive ? "success" : "warning"} className="rounded-full">
                                                        {client.isActive ? "Activo" : "Inactivo"}
                                                    </Badge>
                                                </div>
                                                <div className="flex items-center gap-4 text-sm text-muted-foreground mt-1">
                                                    {client.email && (
                                                        <span className="flex items-center gap-1">
                                                            <Mail size={12} /> {client.email}
                                                        </span>
                                                    )}
                                                    {client.phone && (
                                                        <span className="flex items-center gap-1">
                                                            <Phone size={12} /> {client.phone}
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-8">
                                            <div className="text-right">
                                                <p className="text-lg font-bold">${client.monthlyFee || 0}/mes</p>
                                                <p className="text-xs text-muted-foreground">Día pago: {client.paymentDay || 1}</p>
                                            </div>
                                            <Link href={`/clients/${client.id}`}>
                                                <Button variant="outline" size="sm" className="rounded-xl border-2 group-hover:bg-violet-50 group-hover:border-violet-200">Gestionar</Button>
                                            </Link>
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        </motion.div>
                    ))
                )}
            </div>

            {/* Create Client Modal */}
            <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
                <DialogContent className="max-w-md">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <Users className="w-5 h-5 text-violet-500" />
                            Nuevo Cliente
                        </DialogTitle>
                        <DialogDescription>
                            Agrega un nuevo cliente a tu sistema de gestión.
                        </DialogDescription>
                    </DialogHeader>

                    <form onSubmit={handleSubmit} className="space-y-4 mt-4">
                        <div className="space-y-2">
                            <label className="text-sm font-medium">Nombre *</label>
                            <Input
                                name="name"
                                placeholder="Nombre del cliente"
                                value={formData.name}
                                onChange={handleInputChange}
                                className="rounded-xl border-2"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1">
                                    <Mail size={14} /> Email
                                </label>
                                <Input
                                    name="email"
                                    type="email"
                                    placeholder="email@ejemplo.com"
                                    value={formData.email}
                                    onChange={handleInputChange}
                                    className="rounded-xl border-2"
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1">
                                    <Phone size={14} /> Teléfono
                                </label>
                                <Input
                                    name="phone"
                                    placeholder="+1 234 567 890"
                                    value={formData.phone}
                                    onChange={handleInputChange}
                                    className="rounded-xl border-2"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm font-medium flex items-center gap-1">
                                <Building size={14} /> Empresa
                            </label>
                            <Input
                                name="companyName"
                                placeholder="Nombre de empresa (opcional)"
                                value={formData.companyName}
                                onChange={handleInputChange}
                                className="rounded-xl border-2"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1">
                                    <DollarSign size={14} /> Tarifa Mensual
                                </label>
                                <Input
                                    name="monthlyFee"
                                    type="number"
                                    placeholder="0.00"
                                    value={formData.monthlyFee}
                                    onChange={handleInputChange}
                                    className="rounded-xl border-2"
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1">
                                    <Calendar size={14} /> Día de Pago
                                </label>
                                <Input
                                    name="paymentDay"
                                    type="number"
                                    min="1"
                                    max="31"
                                    placeholder="1"
                                    value={formData.paymentDay}
                                    onChange={handleInputChange}
                                    className="rounded-xl border-2"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm font-medium flex items-center gap-1">
                                <FileText size={14} /> Notas
                            </label>
                            <textarea
                                name="notes"
                                placeholder="Notas adicionales (opcional)"
                                value={formData.notes}
                                onChange={handleInputChange}
                                rows={3}
                                className="w-full px-3 py-2 rounded-xl border-2 border-gray-200 focus:border-violet-300 focus:outline-none resize-none"
                            />
                        </div>

                        <DialogFooter>
                            <Button
                                type="button"
                                variant="outline"
                                onClick={() => setIsModalOpen(false)}
                                className="rounded-xl"
                            >
                                Cancelar
                            </Button>
                            <Button
                                type="submit"
                                disabled={isSubmitting}
                                className="rounded-xl bg-gradient-to-r from-violet-500 to-purple-600"
                            >
                                {isSubmitting ? (
                                    <RefreshCw className="w-4 h-4 animate-spin mr-2" />
                                ) : (
                                    <Plus className="w-4 h-4 mr-2" />
                                )}
                                Crear Cliente
                            </Button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>
        </div >
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Lock, Zap, Loader2 } from "lucide-react";
import { useToast } from "@/components/ui/toast";
import { motion } from "framer-motion";

export default function LoginPage() {
    const [password, setPassword] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const router = useRouter();
    const { addToast } = useToast();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);

        try {
            const res = await fetch("/api/auth/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ password }),
            });

            const data = await res.json();

            if (data.success) {
                addToast("Acceso concedido", "success");
                router.push("/");
                router.refresh();
            } else {
                addToast("Contraseña incorrecta", "error");
            }
        } catch (error) {
            addToast("Error de conexión", "error");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-50 to-purple-50 p-4">
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className="w-full max-w-md"
            >
                <div className="flex justify-center mb-8">
                    <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-violet-500 to-purple-600 flex items-center justify-center shadow-2xl shadow-purple-200">
                        <Zap className="w-8 h-8 text-white" />
                    </div>
                </div>

                <Card className="border-2 border-gray-100 shadow-xl backdrop-blur-sm bg-white/80">
                    <CardHeader className="space-y-1 text-center">
                        <CardTitle className="text-2xl font-bold">RNV Manager</CardTitle>
                        <CardDescription>
                            Ingresa la contraseña maestra para continuar
                        </CardDescription>
                    </CardHeader>
                    <CardContent>
                        <form onSubmit={handleLogin} className="space-y-4">
                            <div className="space-y-2">
                                <div className="relative">
                                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
                                    <Input
                                        type="password"
                                        placeholder="••••••••"
                                        className="pl-10 h-12 border-gray-200 focus:border-violet-500 focus:ring-violet-500"
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                        required
                                    />
                                </div>
                            </div>
                            <Button
                                type="submit"
                                className="w-full h-12 bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white font-semibold shadow-lg shadow-purple-100 transition-all active:scale-[0.98]"
                                disabled={isLoading}
                            >
                                {isLoading ? (
                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                ) : (
                                    "Desbloquear Panel"
                                )}
                            </Button>
                        </form>
                    </CardContent>
                </Card>

                <p className="text-center text-sm text-gray-500 mt-8">
                    © 2025 RNV Manager • Local Environment
                </p>
            </motion.div>
        </div>
    );
}

"use client";

import { Button } from "@/components/ui/button";
import { useToast } from "@/components/ui/toast";
import {
    Activity, Server, Users, DollarSign, TrendingUp, Bell,
    ArrowUpRight, RefreshCw, AlertTriangle, Zap, CreditCard,
    Wifi, WifiOff, Filter, ChevronDown, BarChart3, Clock
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback } from "react";
import Link from "next/link";
import useSWR from "swr";

// Types
interface VPSItem {
    id: string;
    name: string;
    status: string;
    ipAddress: string;
    monthlyCost?: number;
}

interface OverdueClient {
    id: string;
    name: string;
    monthlyFee: number;
    paymentDay: number;
    daysOverdue: number;
}

interface BillingData {
    name: string;
    totalMonthlyCost: number;
}

interface StatsData {
    vps: number;
    clients: number;
    services: number;
    revenue: number;
}

interface ClientData {
    id: string;
    name: string;
    monthlyFee: number;
    paymentDay: number;
    isActive: boolean;
}

// Fetcher for SWR
const fetcher = (url: string) => fetch(url).then(res => res.json());

// Skeleton Components
function StatCardSkeleton() {
    return (
        <div className="bg-gray-100 rounded-2xl p-6 animate-pulse">
            <div className="flex items-start justify-between">
                <div className="space-y-3">
                    <div className="h-4 bg-gray-200 rounded w-24" />
                    <div className="h-10 bg-gray-200 rounded w-16" />
                    <div className="h-3 bg-gray-200 rounded w-32" />
                </div>
                <div className="w-12 h-12 bg-gray-200 rounded-xl" />
            </div>
        </div>
    );
}

function VPSListSkeleton() {
    return (
        <div className="space-y-3">
            {[1, 2, 3, 4, 5].map((i) => (
                <div key={i} className="flex items-center gap-4 p-4 rounded-xl bg-gray-50 animate-pulse">
                    <div className="w-10 h-10 rounded-xl bg-gray-200" />
                    <div className="flex-1 space-y-2">
                        <div className="h-4 bg-gray-200 rounded w-32" />
                        <div className="h-3 bg-gray-200 rounded w-24" />
                    </div>
                    <div className="h-6 bg-gray-200 rounded-full w-16" />
                </div>
            ))}
        </div>
    );
}

function ChartSkeleton() {
    return (
        <div className="space-y-4 animate-pulse">
            {[1, 2, 3, 4, 5, 6].map((i) => (
                <div key={i} className="space-y-2">
                    <div className="flex justify-between">
                        <div className="h-4 bg-gray-200 rounded w-24" />
                        <div className="h-4 bg-gray-200 rounded w-16" />
                    </div>
                    <div className="h-4 bg-gray-100 rounded-full">
                        <div className="h-full bg-gray-200 rounded-full" style={{ width: `${100 - i * 15}%` }} />
                    </div>
                </div>
            ))}
        </div>
    );
}

// Tooltip Component
function Tooltip({ children, content }: { children: React.ReactNode; content: string }) {
    return (
        <div className="relative group">
            {children}
            <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-3 py-1.5 bg-gray-900 text-white text-xs rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-50">
                {content}
                <div className="absolute top-full left-1/2 -translate-x-1/2 -mt-1 border-4 border-transparent border-t-gray-900" />
            </div>
        </div>
    );
}

export default function Home() {
    const { toast } = useToast();
    const [statusFilter, setStatusFilter] = useState<"all" | "running" | "stopped">("all");
    const [showFilterMenu, setShowFilterMenu] = useState(false);
    const [lastRefresh, setLastRefresh] = useState<Date>(new Date());

    // SWR hooks with auto-refresh every 30 seconds
    const { data: statsResponse, error: statsError, isLoading: statsLoading, mutate: mutateStats } = useSWR<{ success: boolean; data: StatsData }>(
        "/api/stats",
        fetcher,
        { refreshInterval: 30000, revalidateOnFocus: true }
    );

    const { data: vpsResponse, error: vpsError, isLoading: vpsLoading, mutate: mutateVps } = useSWR<{ data: VPSItem[] }>(
        "/api/hostinger/vps",
        fetcher,
        { refreshInterval: 30000 }
    );

    const { data: clientsResponse, error: clientsError, isLoading: clientsLoading, mutate: mutateClients } = useSWR<{ success: boolean; data: ClientData[] } | ClientData[]>(
        "/api/clients",
        fetcher,
        { refreshInterval: 60000 }
    );

    const { data: billingResponse, error: billingError, isLoading: billingLoading, mutate: mutateBilling } = useSWR<{ success: boolean; data: BillingData[] }>(
        "/api/billing",
        fetcher,
        { refreshInterval: 60000 }
    );

    // Derived data
    const statsData = statsResponse?.data || { vps: 0, clients: 0, services: 0, revenue: 0 };
    const vpsData = vpsResponse?.data || [];

    const billingData = billingResponse?.success && billingResponse.data
        ? billingResponse.data
            .filter((c) => c.totalMonthlyCost > 0)
            .sort((a, b) => b.totalMonthlyCost - a.totalMonthlyCost)
            .slice(0, 6)
            .map((c) => ({
                name: c.name.length > 12 ? c.name.substring(0, 12) + "..." : c.name,
                totalMonthlyCost: c.totalMonthlyCost
            }))
        : [];

    // Calculate overdue clients
    const overdueClients: OverdueClient[] = (() => {
        const clientsArray = Array.isArray(clientsResponse)
            ? clientsResponse
            : clientsResponse?.data || [];

        if (!Array.isArray(clientsArray)) return [];

        const today = new Date().getDate();
        return clientsArray
            .filter((c) => c.paymentDay && today > c.paymentDay && c.isActive)
            .map((c) => ({
                id: c.id,
                name: c.name,
                monthlyFee: c.monthlyFee || 0,
                paymentDay: c.paymentDay,
                daysOverdue: today - c.paymentDay
            }))
            .sort((a, b) => b.daysOverdue - a.daysOverdue);
    })();

    // Filter VPS by status
    const filteredVps = vpsData.filter(vps => {
        if (statusFilter === "all") return true;
        return vps.status === statusFilter;
    });

    // Manual refresh
    const handleRefresh = useCallback(async () => {
        toast({
            title: "Actualizando...",
            description: "Obteniendo datos más recientes",
        });

        await Promise.all([
            mutateStats(),
            mutateVps(),
            mutateClients(),
            mutateBilling()
        ]);

        setLastRefresh(new Date());

        toast({
            title: "✅ Actualizado",
            description: "Todos los datos están al día",
        });
    }, [mutateStats, mutateVps, mutateClients, mutateBilling, toast]);

    // Show errors
    useEffect(() => {
        if (statsError || vpsError || clientsError || billingError) {
            toast({
                title: "Error de conexión",
                description: "No se pudieron cargar algunos datos",
                variant: "destructive",
            });
        }
    }, [statsError, vpsError, clientsError, billingError, toast]);

    const isLoading = statsLoading || vpsLoading;
    const hasError = statsError || vpsError;

    const stats = [
        {
            title: "VPS Managed",
            value: statsData.vps,
            subtitle: `${vpsData.filter((v) => v.status === "running").length} activos ahora`,
            icon: Server,
            color: "from-violet-500 to-purple-600",
            bgColor: "bg-violet-50 dark:bg-violet-950",
            href: "/vps",
            tooltip: "Total de servidores VPS administrados"
        },
        {
            title: "Clientes",
            value: statsData.clients,
            subtitle: "En base de datos",
            icon: Users,
            color: "from-blue-500 to-cyan-500",
            bgColor: "bg-blue-50 dark:bg-blue-950",
            href: "/clients",
            tooltip: "Clientes registrados en el sistema"
        },
        {
            title: "Ingresos",
            value: `$${statsData.revenue.toLocaleString()}`,
            subtitle: "Total mensual",
            icon: DollarSign,
            color: "from-green-500 to-emerald-500",
            bgColor: "bg-green-50 dark:bg-green-950",
            href: "/billing",
            tooltip: "Suma de todos los servicios mensuales"
        },
        {
            title: "Servicios",
            value: statsData.services,
            subtitle: "Instancias activas",
            icon: Activity,
            color: "from-orange-500 to-rose-500",
            bgColor: "bg-orange-50 dark:bg-orange-950",
            href: "/services",
            tooltip: "Servicios desplegados (Odoo, web, etc.)"
        },
    ];

    const quickActions = [
        { label: "Ver Servidores", icon: Server, href: "/vps", primary: true },
        { label: "Facturación", icon: DollarSign, href: "/billing" },
        { label: "Gestionar Clientes", icon: Users, href: "/clients" },
        { label: "Pizarra Blanca", icon: Zap, href: "/whiteboard", badge: "NUEVO" },
    ];

    return (
        <div className="space-y-8">
            {/* Header */}
            <div className="flex items-center justify-between flex-wrap gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-gray-900 dark:text-white">Panel Principal</h1>
                    <p className="text-gray-500 dark:text-gray-400 mt-1">¡Bienvenido de vuelta! Aquí está tu resumen.</p>
                </div>
                <div className="flex items-center gap-3">
                    {/* Connection Status */}
                    <Tooltip content={hasError ? "Error de conexión" : "Conectado"}>
                        <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm ${hasError
                                ? "bg-red-100 text-red-700 dark:bg-red-900 dark:text-red-300"
                                : "bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300"
                            }`}>
                            {hasError ? <WifiOff size={14} /> : <Wifi size={14} />}
                            {hasError ? "Desconectado" : "En línea"}
                        </div>
                    </Tooltip>

                    {/* Last Updated */}
                    <Tooltip content={`Última actualización: ${lastRefresh.toLocaleTimeString()}`}>
                        <div className="text-sm text-gray-500 dark:text-gray-400 flex items-center gap-1">
                            <Clock size={14} />
                            {lastRefresh.toLocaleTimeString("es-ES", { hour: "2-digit", minute: "2-digit" })}
                        </div>
                    </Tooltip>

                    {/* Refresh Button */}
                    <Tooltip content="Actualizar datos (auto cada 30s)">
                        <Button
                            variant="outline"
                            size="icon"
                            onClick={handleRefresh}
                            className="border-2 border-gray-200 hover:border-violet-300 dark:border-gray-700"
                        >
                            <RefreshCw size={18} className={isLoading ? "animate-spin" : ""} />
                        </Button>
                    </Tooltip>

                    {/* Notifications */}
                    <Tooltip content={overdueClients.length > 0 ? `${overdueClients.length} pagos vencidos` : "Sin alertas"}>
                        <Button variant="outline" size="icon" className="relative border-2 border-gray-200 hover:border-violet-300 dark:border-gray-700">
                            <Bell size={18} />
                            <AnimatePresence>
                                {overdueClients.length > 0 && (
                                    <motion.span
                                        initial={{ scale: 0 }}
                                        animate={{ scale: 1 }}
                                        exit={{ scale: 0 }}
                                        className="absolute -top-1 -right-1 h-5 w-5 rounded-full bg-red-500 text-[10px] text-white flex items-center justify-center font-bold"
                                    >
                                        {overdueClients.length}
                                    </motion.span>
                                )}
                            </AnimatePresence>
                        </Button>
                    </Tooltip>

                    {/* Date */}
                    <div className="text-right hidden md:block">
                        <p className="text-sm text-gray-500 dark:text-gray-400">{new Date().toLocaleDateString("es-ES", { weekday: "long" })}</p>
                        <p className="text-lg font-semibold text-gray-900 dark:text-white">{new Date().toLocaleDateString("es-ES", { day: "numeric", month: "short", year: "numeric" })}</p>
                    </div>
                </div>
            </div>

            {/* Overdue Payment Alert */}
            <AnimatePresence>
                {overdueClients.length > 0 && (
                    <motion.div
                        initial={{ opacity: 0, y: -10, height: 0 }}
                        animate={{ opacity: 1, y: 0, height: "auto" }}
                        exit={{ opacity: 0, y: -10, height: 0 }}
                        className="bg-gradient-to-r from-red-50 to-orange-50 dark:from-red-950 dark:to-orange-950 border-2 border-red-200 dark:border-red-800 rounded-2xl p-4"
                    >
                        <div className="flex items-start gap-4">
                            <div className="p-3 rounded-xl bg-red-100 dark:bg-red-900">
                                <AlertTriangle className="w-6 h-6 text-red-500" />
                            </div>
                            <div className="flex-1">
                                <h3 className="font-bold text-red-800 dark:text-red-200 flex items-center gap-2">
                                    <CreditCard size={16} />
                                    {overdueClients.length} Cliente{overdueClients.length > 1 ? "s" : ""} con Pago Vencido
                                </h3>
                                <div className="mt-2 space-y-1">
                                    {overdueClients.slice(0, 3).map(client => (
                                        <div key={client.id} className="flex items-center justify-between text-sm">
                                            <span className="text-red-700 dark:text-red-300">
                                                <span className="font-medium">{client.name}</span>
                                                <span className="text-red-500 dark:text-red-400 ml-2">({client.daysOverdue} días)</span>
                                            </span>
                                            <span className="font-bold text-red-800 dark:text-red-200">${client.monthlyFee}</span>
                                        </div>
                                    ))}
                                    {overdueClients.length > 3 && (
                                        <p className="text-xs text-red-500">+ {overdueClients.length - 3} más...</p>
                                    )}
                                </div>
                                <Link href="/clients">
                                    <Button size="sm" className="mt-3 bg-red-500 hover:bg-red-600 text-white rounded-lg gap-1">
                                        Ver Todos <ArrowUpRight size={14} />
                                    </Button>
                                </Link>
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Stats Grid */}
            <div className="grid gap-4 sm:gap-6 grid-cols-2 lg:grid-cols-4">
                {isLoading ? (
                    <>
                        <StatCardSkeleton />
                        <StatCardSkeleton />
                        <StatCardSkeleton />
                        <StatCardSkeleton />
                    </>
                ) : (
                    stats.map((stat, index) => (
                        <Tooltip key={stat.title} content={stat.tooltip}>
                            <Link href={stat.href}>
                                <motion.div
                                    initial={{ opacity: 0, y: 20 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    transition={{ delay: index * 0.1 }}
                                    whileHover={{ scale: 1.02, y: -2 }}
                                    whileTap={{ scale: 0.98 }}
                                    className={`${stat.bgColor} rounded-2xl p-4 sm:p-6 border-2 border-transparent hover:border-violet-200 dark:hover:border-violet-700 transition-all cursor-pointer group relative overflow-hidden`}
                                >
                                    <div className="flex items-start justify-between relative z-10">
                                        <div>
                                            <p className="text-xs sm:text-sm font-medium text-gray-600 dark:text-gray-400">{stat.title}</p>
                                            <p className="text-2xl sm:text-4xl font-bold text-gray-900 dark:text-white mt-1 sm:mt-2">
                                                {typeof stat.value === "number" ? stat.value : stat.value}
                                            </p>
                                            <p className="text-xs sm:text-sm text-gray-500 dark:text-gray-400 mt-1 sm:mt-2 flex items-center gap-1">
                                                <TrendingUp size={14} className="text-green-500" />
                                                {stat.subtitle}
                                            </p>
                                        </div>
                                        <div className={`p-2 sm:p-3 rounded-xl bg-gradient-to-br ${stat.color} shadow-lg group-hover:scale-110 transition-transform`}>
                                            <stat.icon className="w-5 h-5 sm:w-6 sm:h-6 text-white" />
                                        </div>
                                    </div>
                                    <div className="absolute -right-8 -bottom-8 w-24 sm:w-32 h-24 sm:h-32 rounded-full bg-white/30 dark:bg-white/10 group-hover:scale-150 transition-transform duration-500" />
                                </motion.div>
                            </Link>
                        </Tooltip>
                    ))
                )}
            </div>

            {/* Main Content */}
            <div className="grid gap-6 lg:grid-cols-3">
                {/* VPS Quick View */}
                <div className="lg:col-span-2 bg-white dark:bg-gray-900 rounded-2xl border-2 border-gray-100 dark:border-gray-800 p-6 shadow-sm">
                    <div className="flex items-center justify-between mb-6 flex-wrap gap-3">
                        <div>
                            <h2 className="text-lg font-bold text-gray-900 dark:text-white">Servidores VPS</h2>
                            <p className="text-sm text-gray-500 dark:text-gray-400">{filteredVps.length} de {vpsData.length} servidores</p>
                        </div>
                        <div className="flex items-center gap-2">
                            {/* Filter Dropdown */}
                            <div className="relative">
                                <Button
                                    variant="outline"
                                    size="sm"
                                    onClick={() => setShowFilterMenu(!showFilterMenu)}
                                    className="gap-1 dark:border-gray-700"
                                >
                                    <Filter size={14} />
                                    {statusFilter === "all" ? "Todos" : statusFilter === "running" ? "Activos" : "Detenidos"}
                                    <ChevronDown size={14} />
                                </Button>
                                <AnimatePresence>
                                    {showFilterMenu && (
                                        <motion.div
                                            initial={{ opacity: 0, y: -10 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            exit={{ opacity: 0, y: -10 }}
                                            className="absolute right-0 top-full mt-1 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg shadow-lg py-1 z-50 min-w-[120px]"
                                        >
                                            {[
                                                { value: "all", label: "Todos" },
                                                { value: "running", label: "Activos" },
                                                { value: "stopped", label: "Detenidos" }
                                            ].map((option) => (
                                                <button
                                                    key={option.value}
                                                    onClick={() => {
                                                        setStatusFilter(option.value as any);
                                                        setShowFilterMenu(false);
                                                    }}
                                                    className={`w-full px-3 py-2 text-left text-sm hover:bg-gray-100 dark:hover:bg-gray-700 ${statusFilter === option.value ? "text-violet-600 font-medium" : "text-gray-700 dark:text-gray-300"
                                                        }`}
                                                >
                                                    {option.label}
                                                </button>
                                            ))}
                                        </motion.div>
                                    )}
                                </AnimatePresence>
                            </div>
                            <Link href="/vps">
                                <Button variant="ghost" size="sm" className="text-violet-600 hover:text-violet-700 hover:bg-violet-50 dark:hover:bg-violet-950 gap-1">
                                    Ver todos <ArrowUpRight size={14} />
                                </Button>
                            </Link>
                        </div>
                    </div>

                    {vpsLoading ? (
                        <VPSListSkeleton />
                    ) : filteredVps.length === 0 ? (
                        <div className="text-center py-12 text-gray-500 dark:text-gray-400">
                            <Server className="w-12 h-12 mx-auto mb-3 opacity-50" />
                            <p>No hay servidores {statusFilter !== "all" ? `con estado "${statusFilter}"` : ""}</p>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {filteredVps.slice(0, 5).map((vps, index) => (
                                <motion.div
                                    key={vps.id}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: index * 0.05 }}
                                    whileHover={{ x: 4 }}
                                    className="flex items-center gap-4 p-4 rounded-xl bg-gray-50 dark:bg-gray-800 hover:bg-violet-50 dark:hover:bg-violet-950/50 transition-colors group cursor-pointer"
                                >
                                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${vps.status === "running"
                                            ? "bg-green-100 dark:bg-green-900"
                                            : "bg-gray-200 dark:bg-gray-700"
                                        }`}>
                                        <Server className={`w-5 h-5 ${vps.status === "running"
                                                ? "text-green-600 dark:text-green-400"
                                                : "text-gray-400"
                                            }`} />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className="font-semibold text-gray-900 dark:text-white truncate">{vps.name}</p>
                                        <p className="text-sm text-gray-500 dark:text-gray-400 font-mono">{vps.ipAddress}</p>
                                    </div>
                                    <span className={`px-3 py-1 rounded-full text-xs font-medium ${vps.status === "running"
                                            ? "bg-green-100 dark:bg-green-900 text-green-700 dark:text-green-300"
                                            : "bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-400"
                                        }`}>
                                        {vps.status === "running" ? "Activo" : vps.status}
                                    </span>
                                </motion.div>
                            ))}
                        </div>
                    )}
                </div>

                {/* Quick Actions */}
                <div className="bg-white dark:bg-gray-900 rounded-2xl border-2 border-gray-100 dark:border-gray-800 p-6 shadow-sm">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white mb-6">Acciones Rápidas</h2>
                    <div className="space-y-3">
                        {quickActions.map((action, index) => (
                            <Link key={action.label} href={action.href}>
                                <motion.div
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    transition={{ delay: 0.3 + index * 0.1 }}
                                    whileHover={{ scale: 1.02 }}
                                    whileTap={{ scale: 0.98 }}
                                >
                                    <Button
                                        className={`w-full justify-start gap-3 h-12 ${action.primary
                                            ? "bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white shadow-lg shadow-purple-200 dark:shadow-purple-900"
                                            : "bg-gray-50 dark:bg-gray-800 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 border-0"
                                            }`}
                                        variant={action.primary ? "default" : "outline"}
                                    >
                                        <action.icon size={18} />
                                        {action.label}
                                        {action.badge && (
                                            <span className="ml-auto text-[10px] bg-violet-600 text-white px-2 py-0.5 rounded-full animate-pulse">
                                                {action.badge}
                                            </span>
                                        )}
                                    </Button>
                                </motion.div>
                            </Link>
                        ))}
                    </div>

                    {/* Tip Card */}
                    <motion.div
                        className="mt-6 p-4 rounded-xl bg-gradient-to-br from-violet-50 to-purple-50 dark:from-violet-950 dark:to-purple-950 border border-violet-100 dark:border-violet-800"
                        whileHover={{ scale: 1.02 }}
                    >
                        <div className="flex items-start gap-3">
                            <div className="p-2 rounded-lg bg-violet-100 dark:bg-violet-900">
                                <BarChart3 className="w-4 h-4 text-violet-600 dark:text-violet-400" />
                            </div>
                            <div>
                                <p className="text-sm font-medium text-gray-900 dark:text-white">Auto-refresh activo</p>
                                <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">Los datos se actualizan cada 30 segundos</p>
                            </div>
                        </div>
                    </motion.div>
                </div>
            </div>

            {/* Revenue Chart */}
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.4 }}
                className="bg-white dark:bg-gray-900 rounded-2xl border-2 border-gray-100 dark:border-gray-800 p-6 shadow-sm"
            >
                <div className="flex items-center justify-between mb-6 flex-wrap gap-3">
                    <div>
                        <h2 className="text-lg font-bold text-gray-900 dark:text-white">Ingresos por Cliente</h2>
                        <p className="text-sm text-gray-500 dark:text-gray-400">
                            {billingLoading ? "Cargando..." : `Top ${billingData.length} clientes por facturación mensual`}
                        </p>
                    </div>
                    <Link href="/billing">
                        <Button variant="ghost" size="sm" className="text-violet-600 hover:text-violet-700 hover:bg-violet-50 dark:hover:bg-violet-950 gap-1">
                            Ver Billing <ArrowUpRight size={14} />
                        </Button>
                    </Link>
                </div>

                {billingLoading ? (
                    <ChartSkeleton />
                ) : billingData.length === 0 ? (
                    <div className="text-center py-12 text-gray-500 dark:text-gray-400">
                        <DollarSign className="w-12 h-12 mx-auto mb-3 opacity-50" />
                        <p>No hay datos de facturación</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {billingData.map((item, index) => {
                            const maxValue = Math.max(...billingData.map(d => d.totalMonthlyCost));
                            const percentage = (item.totalMonthlyCost / maxValue) * 100;
                            return (
                                <motion.div
                                    key={item.name}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.5 + index * 0.1 }}
                                    className="group"
                                >
                                    <div className="flex items-center justify-between mb-1">
                                        <span className="text-sm font-medium text-gray-700 dark:text-gray-300">{item.name}</span>
                                        <span className="text-sm font-bold text-green-600 dark:text-green-400">${item.totalMonthlyCost.toFixed(2)}</span>
                                    </div>
                                    <div className="h-4 bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
                                        <motion.div
                                            initial={{ width: 0 }}
                                            animate={{ width: `${percentage}%` }}
                                            transition={{ delay: 0.6 + index * 0.1, duration: 0.5 }}
                                            className="h-full bg-gradient-to-r from-green-400 to-emerald-500 rounded-full group-hover:from-green-500 group-hover:to-emerald-600 transition-colors"
                                        />
                                    </div>
                                </motion.div>
                            );
                        })}
                    </div>
                )}
            </motion.div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";

interface Service {
    id: string;
    name: string;
    type: string;
    port?: number;
    url?: string;
    configFile?: string;
    monthlyCost: number;
    status: string;
    resourceUsage?: any;
    vps?: { id: string; name: string; ipAddress: string } | null;
    client?: { id: string; name: string } | null;
    createdAt: string;
    updatedAt: string;
}

interface Client {
    id: string;
    name: string;
}

interface VPS {
    id: string;
    name: string;
    ipAddress: string;
}

export default function ServiceDetailPage() {
    const params = useParams();
    const router = useRouter();
    const serviceId = params.id as string;

    const [service, setService] = useState<Service | null>(null);
    const [clients, setClients] = useState<Client[]>([]);
    const [vpsList, setVpsList] = useState<VPS[]>([]);
    const [loading, setLoading] = useState(true);
    const [editing, setEditing] = useState(false);
    const [saving, setSaving] = useState(false);

    const [form, setForm] = useState({
        name: "",
        type: "odoo",
        url: "",
        port: 0,
        monthlyCost: 0,
        configFile: "",
        clientId: "",
        vpsId: "",
        status: "running",
    });

    useEffect(() => {
        fetchService();
        fetchClients();
        fetchVPS();
    }, [serviceId]);

    const fetchService = async () => {
        try {
            const res = await fetch(`/api/services/${serviceId}`);
            const data = await res.json();
            if (data.success) {
                setService(data.data);
                setForm({
                    name: data.data.name,
                    type: data.data.type,
                    url: data.data.url || "",
                    port: data.data.port || 0,
                    monthlyCost: data.data.monthlyCost || 0,
                    configFile: data.data.configFile || "",
                    clientId: data.data.client?.id || "",
                    vpsId: data.data.vps?.id || "",
                    status: data.data.status || "running",
                });
            }
        } catch (err) {
            console.error("Error fetching service:", err);
        } finally {
            setLoading(false);
        }
    };

    const fetchClients = async () => {
        try {
            const res = await fetch("/api/clients");
            const data = await res.json();
            if (data.success) {
                setClients(data.data);
            }
        } catch (err) {
            console.error("Error fetching clients:", err);
        }
    };

    const fetchVPS = async () => {
        try {
            const res = await fetch("/api/vps");
            const data = await res.json();
            if (data.success) {
                setVpsList(data.data);
            }
        } catch (err) {
            console.error("Error fetching VPS:", err);
        }
    };

    const handleSave = async () => {
        setSaving(true);
        try {
            const res = await fetch(`/api/services/${serviceId}`, {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(form),
            });
            const data = await res.json();
            if (data.success) {
                setService(data.data);
                setEditing(false);
                fetchService(); // Reload with relations
            }
        } catch (err) {
            console.error("Error saving service:", err);
        } finally {
            setSaving(false);
        }
    };

    const handleDelete = async () => {
        if (!confirm("Are you sure you want to delete this service?")) return;

        try {
            const res = await fetch(`/api/services/${serviceId}`, {
                method: "DELETE",
            });
            const data = await res.json();
            if (data.success) {
                router.push(service?.vps ? `/vps/${service.vps.id}` : "/services");
            }
        } catch (err) {
            console.error("Error deleting service:", err);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-900 text-white p-8 flex items-center justify-center">
                <div className="animate-spin rounded-full h-12 w-12 border-4 border-cyan-500 border-t-transparent"></div>
            </div>
        );
    }

    if (!service) {
        return (
            <div className="min-h-screen bg-gray-900 text-white p-8">
                <p>Service not found</p>
                <Link href="/services" className="text-cyan-400 hover:underline">← Back to Services</Link>
            </div>
        );
    }

    const serviceUrl = service.url || `https://${service.name}.renace.tech`;

    return (
        <div className="min-h-screen bg-gray-900 text-white p-8">
            {/* Header */}
            <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-4">
                    <Link href={service.vps ? `/vps/${service.vps.id}` : "/services"} className="text-gray-400 hover:text-white">
                        ← Back
                    </Link>
                    <h1 className="text-3xl font-bold">{service.name}</h1>
                    <span className={`px-3 py-1 text-xs rounded-full ${service.type === "odoo" ? "bg-purple-500/20 text-purple-400" :
                            service.type === "web" ? "bg-blue-500/20 text-blue-400" :
                                service.type === "api" ? "bg-orange-500/20 text-orange-400" :
                                    service.type === "database" ? "bg-green-500/20 text-green-400" :
                                        "bg-gray-500/20 text-gray-400"
                        }`}>
                        {service.type.toUpperCase()}
                    </span>
                </div>
                <div className="flex gap-2">
                    <button
                        onClick={() => setEditing(!editing)}
                        className="px-4 py-2 bg-cyan-600 hover:bg-cyan-700 rounded-lg transition"
                    >
                        {editing ? "Cancel" : "Edit"}
                    </button>
                    <button
                        onClick={handleDelete}
                        className="px-4 py-2 bg-red-600 hover:bg-red-700 rounded-lg transition"
                    >
                        Delete
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Service Info */}
                <div className="bg-gray-800 rounded-xl p-6 border border-gray-700">
                    <h2 className="text-xl font-semibold mb-4">Service Details</h2>

                    {editing ? (
                        <div className="space-y-4">
                            <div>
                                <label className="text-sm text-gray-400">Name (Subdomain)</label>
                                <input
                                    type="text"
                                    value={form.name}
                                    onChange={(e) => setForm({ ...form, name: e.target.value })}
                                    className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                />
                                <p className="text-xs text-gray-500 mt-1">→ {form.name}.renace.tech</p>
                            </div>
                            <div>
                                <label className="text-sm text-gray-400">Type</label>
                                <select
                                    value={form.type}
                                    onChange={(e) => setForm({ ...form, type: e.target.value })}
                                    className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                >
                                    <option value="odoo">Odoo</option>
                                    <option value="web">Web</option>
                                    <option value="api">API</option>
                                    <option value="database">Database</option>
                                    <option value="storage">Storage</option>
                                    <option value="ai">AI</option>
                                    <option value="other">Other</option>
                                </select>
                            </div>
                            <div>
                                <label className="text-sm text-gray-400">Custom URL (optional)</label>
                                <input
                                    type="url"
                                    value={form.url}
                                    onChange={(e) => setForm({ ...form, url: e.target.value })}
                                    placeholder="https://..."
                                    className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm text-gray-400">Port</label>
                                    <input
                                        type="number"
                                        value={form.port || ""}
                                        onChange={(e) => setForm({ ...form, port: parseInt(e.target.value) || 0 })}
                                        className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="text-sm text-gray-400">Cost ($/mo)</label>
                                    <input
                                        type="number"
                                        value={form.monthlyCost || ""}
                                        onChange={(e) => setForm({ ...form, monthlyCost: parseFloat(e.target.value) || 0 })}
                                        className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="text-sm text-gray-400">Config File Path</label>
                                <input
                                    type="text"
                                    value={form.configFile}
                                    onChange={(e) => setForm({ ...form, configFile: e.target.value })}
                                    placeholder="/etc/nginx/sites-available/..."
                                    className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                />
                            </div>
                            <div>
                                <label className="text-sm text-gray-400">Assign to VPS</label>
                                <select
                                    value={form.vpsId}
                                    onChange={(e) => setForm({ ...form, vpsId: e.target.value })}
                                    className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                >
                                    <option value="">-- No VPS --</option>
                                    {vpsList.map((v) => (
                                        <option key={v.id} value={v.id}>{v.name} ({v.ipAddress})</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="text-sm text-gray-400">Assign to Client</label>
                                <select
                                    value={form.clientId}
                                    onChange={(e) => setForm({ ...form, clientId: e.target.value })}
                                    className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                >
                                    <option value="">-- No Client --</option>
                                    {clients.map((c) => (
                                        <option key={c.id} value={c.id}>{c.name}</option>
                                    ))}
                                </select>
                            </div>
                            <button
                                onClick={handleSave}
                                disabled={saving}
                                className="w-full py-2 bg-green-600 hover:bg-green-700 rounded-lg transition disabled:opacity-50"
                            >
                                {saving ? "Saving..." : "Save Changes"}
                            </button>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {/* URL Link */}
                            <a
                                href={serviceUrl}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="block text-center py-3 bg-gradient-to-r from-cyan-600 to-blue-600 rounded-lg hover:opacity-90 transition font-semibold"
                            >
                                🔗 Open {serviceUrl}
                            </a>

                            <div className="space-y-3 mt-6">
                                <div className="flex justify-between">
                                    <span className="text-gray-400">Type</span>
                                    <span className="capitalize">{service.type}</span>
                                </div>
                                {service.port && (
                                    <div className="flex justify-between">
                                        <span className="text-gray-400">Port</span>
                                        <span className="font-mono">{service.port}</span>
                                    </div>
                                )}
                                <div className="flex justify-between">
                                    <span className="text-gray-400">Status</span>
                                    <span className={`${service.status === "running" ? "text-green-400" :
                                            service.status === "stopped" ? "text-red-400" :
                                                "text-yellow-400"
                                        }`}>
                                        {service.status}
                                    </span>
                                </div>
                                <hr className="border-gray-700" />
                                <div className="flex justify-between">
                                    <span className="text-gray-400">Monthly Cost</span>
                                    <span className="text-green-400 font-semibold">${service.monthlyCost}/mo</span>
                                </div>
                                <hr className="border-gray-700" />
                                <div className="flex justify-between">
                                    <span className="text-gray-400">VPS</span>
                                    {service.vps ? (
                                        <Link href={`/vps/${service.vps.id}`} className="text-cyan-400 hover:underline">
                                            {service.vps.name}
                                        </Link>
                                    ) : (
                                        <span className="text-yellow-400">Not assigned</span>
                                    )}
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-gray-400">Client</span>
                                    {service.client ? (
                                        <Link href={`/clients/${service.client.id}`} className="text-cyan-400 hover:underline">
                                            {service.client.name}
                                        </Link>
                                    ) : (
                                        <span className="text-yellow-400">Not assigned</span>
                                    )}
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Config File */}
                <div className="bg-gray-800 rounded-xl p-6 border border-gray-700">
                    <h2 className="text-xl font-semibold mb-4">Configuration</h2>

                    {service.configFile ? (
                        <div className="space-y-4">
                            <div className="bg-gray-900 rounded-lg p-4 font-mono text-sm">
                                <p className="text-gray-400 text-xs mb-2">Config Path:</p>
                                <p className="text-cyan-400 break-all">{service.configFile}</p>
                            </div>
                            <Link
                                href={`/config-editor?path=${encodeURIComponent(service.configFile)}&vps=${service.vps?.id}`}
                                className="block text-center py-2 border border-cyan-500 text-cyan-400 rounded-lg hover:bg-cyan-500/10 transition"
                            >
                                📝 Open Config Editor
                            </Link>
                        </div>
                    ) : (
                        <div className="text-center py-8 text-gray-500">
                            <p>No config file attached</p>
                            <button
                                onClick={() => setEditing(true)}
                                className="mt-4 text-cyan-400 hover:underline"
                            >
                                + Add config path
                            </button>
                        </div>
                    )}

                    {/* Quick Info */}
                    <div className="mt-6 pt-6 border-t border-gray-700">
                        <h3 className="text-sm font-semibold text-gray-400 mb-3">Quick SSH Commands</h3>
                        {service.vps && (
                            <div className="space-y-2">
                                <div className="bg-gray-900 rounded p-2 font-mono text-xs text-gray-300">
                                    ssh root@{service.vps.ipAddress}
                                </div>
                                {service.type === "odoo" && (
                                    <div className="bg-gray-900 rounded p-2 font-mono text-xs text-gray-300">
                                        docker logs {service.name}_odoo
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Database, Settings, Search, Play, Pause, RotateCw, FileCode, Plus, Server, Globe, ExternalLink } from "lucide-react";
import { motion } from "framer-motion";
import { useToast } from "@/components/ui/toast";

export default function ServicesPage() {
    const [services, setServices] = useState<any[]>([]);
    const [vpsList, setVpsList] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const { addToast } = useToast();

    // Form state
    const [formData, setFormData] = useState({
        name: "",
        type: "odoo",
        port: "",
        status: "running",
        vpsId: "",
        url: "",
    });

    const fetchServices = () => {
        setIsLoading(true);
        fetch("/api/services")
            .then(res => res.json())
            .then(response => {
                // Handle both old { data: [...] } and new array format
                const data = response.data || response;
                setServices(Array.isArray(data) ? data : []);
                setIsLoading(false);
            })
            .catch(err => {
                console.error("Error fetching services:", err);
                setIsLoading(false);
            });
    };

    const fetchVps = () => {
        fetch("/api/vps")
            .then(res => res.json())
            .then(response => {
                // Handle both old { data: [...] } and new array format
                const data = response.data || response;
                setVpsList(Array.isArray(data) ? data : []);
            })
            .catch(err => console.error("Error fetching VPS:", err));
    };

    useEffect(() => {
        fetchServices();
        fetchVps();
    }, []);

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name.trim()) {
            addToast("El nombre es requerido", "error");
            return;
        }

        setIsSubmitting(true);
        try {
            const response = await fetch("/api/services", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    name: formData.name,
                    type: formData.type,
                    port: parseInt(formData.port) || null,
                    status: formData.status,
                    vpsId: formData.vpsId || null,
                    url: formData.url || null,
                }),
            });

            if (response.ok) {
                addToast("Servicio creado exitosamente", "success");
                setIsModalOpen(false);
                setFormData({ name: "", type: "odoo", port: "", status: "running", vpsId: "", url: "" });
                fetchServices();
            } else {
                const error = await response.json();
                addToast(error.error || "Error al crear servicio", "error");
            }
        } catch (error) {
            addToast("Error de conexión", "error");
        } finally {
            setIsSubmitting(false);
        }
    };

    const filteredServices = services.filter(s =>
        s.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        s.type.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const serviceIcons: Record<string, any> = {
        odoo: "🟣",
        postgres: "🐘",
        nginx: "🟢",
        redis: "🔴",
        mysql: "🐬",
        docker: "🐳",
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight">Servicios</h2>
                    <p className="text-muted-foreground">Monitorea y gestiona tus servicios en ejecución</p>
                </div>
                <Button
                    onClick={() => setIsModalOpen(true)}
                    className="gap-2 bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 shadow-lg shadow-purple-200"
                >
                    <Plus size={16} />
                    Agregar Servicio
                </Button>
            </div>

            {/* Search & Filters */}
            <div className="flex gap-4">
                <div className="relative flex-1 max-w-sm">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder="Buscar servicios..."
                        className="pl-9 rounded-xl border-2"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
                <Button variant="outline" className="rounded-xl border-2">Filtrar</Button>
            </div>

            {/* Services Table */}
            <Card className="bg-white/70 backdrop-blur rounded-2xl border-2 border-gray-100 shadow-sm">
                <CardHeader>
                    <CardTitle className="text-lg">Servicios Activos ({services.length})</CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="space-y-2">
                        {isLoading ? (
                            <div className="flex justify-center py-12">
                                <RotateCw className="w-8 h-8 text-violet-500 animate-spin" />
                            </div>
                        ) : filteredServices.length === 0 ? (
                            <div className="py-12 text-center">
                                <Database className="w-12 h-12 text-gray-300 mx-auto mb-2" />
                                <p className="text-gray-500 font-medium">No hay servicios registrados</p>
                                <p className="text-sm text-gray-400 mb-4">Agrega tus servicios para comenzar el monitoreo.</p>
                                <Button
                                    onClick={() => setIsModalOpen(true)}
                                    className="gap-2"
                                >
                                    <Plus size={16} />
                                    Agregar Servicio
                                </Button>
                            </div>
                        ) : (
                            filteredServices.map((service, index) => (
                                <motion.div
                                    key={service.id}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: index * 0.05 }}
                                    className="flex items-center justify-between p-4 rounded-xl bg-gray-50 hover:bg-violet-50 transition-colors group border border-transparent hover:border-violet-100"
                                >
                                    <div className="flex items-center gap-4">
                                        <span className="text-2xl">{serviceIcons[service.type] || "⚙️"}</span>
                                        <div>
                                            <div className="flex items-center gap-2">
                                                <Link
                                                    href={`/services/${service.id}`}
                                                    className="font-bold text-gray-900 hover:text-violet-600 transition-colors"
                                                >
                                                    {service.name}
                                                </Link>
                                                <Badge variant="outline" className="text-[10px] uppercase font-bold text-violet-600 bg-violet-50 border-violet-100">{service.type}</Badge>
                                            </div>
                                            <div className="flex items-center gap-2 text-sm text-gray-500">
                                                <span>{service.vps?.name || "Sin VPS"} • Puerto {service.port || "N/A"}</span>
                                                {service.url && (
                                                    <a
                                                        href={service.url}
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="flex items-center gap-1 text-cyan-500 hover:text-cyan-600"
                                                    >
                                                        <ExternalLink size={12} />
                                                        Abrir
                                                    </a>
                                                )}
                                            </div>
                                        </div>
                                    </div>

                                    <div className="flex items-center gap-4">
                                        <Badge variant={service.status === "running" ? "success" : "destructive"} className="rounded-full px-3">
                                            {service.status === "running" ? "Ejecutando" : "Detenido"}
                                        </Badge>

                                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            {service.status === "running" ? (
                                                <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-red-50 hover:text-red-500" title="Stop">
                                                    <Pause size={14} />
                                                </Button>
                                            ) : (
                                                <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-green-50 hover:text-green-500" title="Start">
                                                    <Play size={14} />
                                                </Button>
                                            )}
                                            <Button variant="ghost" size="icon" className="h-8 w-8" title="Restart">
                                                <RotateCw size={14} />
                                            </Button>
                                            <Button variant="ghost" size="icon" className="h-8 w-8" title="Settings">
                                                <Settings size={14} />
                                            </Button>
                                        </div>
                                    </div>
                                </motion.div>
                            ))
                        )}
                    </div>
                </CardContent>
            </Card>

            {/* Create Service Modal */}
            <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
                <DialogContent className="max-w-md">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <Database className="w-5 h-5 text-violet-500" />
                            Nuevo Servicio
                        </DialogTitle>
                        <DialogDescription>
                            Registra un nuevo servicio para monitorear.
                        </DialogDescription>
                    </DialogHeader>

                    <form onSubmit={handleSubmit} className="space-y-4 mt-4">
                        <div className="space-y-2">
                            <label className="text-sm font-medium">Nombre *</label>
                            <Input
                                name="name"
                                placeholder="Ej: Odoo Producción"
                                value={formData.name}
                                onChange={handleInputChange}
                                className="rounded-xl border-2"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1">
                                    <Database size={14} /> Tipo
                                </label>
                                <select
                                    name="type"
                                    value={formData.type}
                                    onChange={handleInputChange}
                                    className="w-full px-3 py-2 rounded-xl border-2 border-gray-200 focus:border-violet-300 focus:outline-none bg-white"
                                >
                                    <option value="odoo">🟣 Odoo</option>
                                    <option value="postgres">🐘 PostgreSQL</option>
                                    <option value="nginx">🟢 Nginx</option>
                                    <option value="redis">🔴 Redis</option>
                                    <option value="mysql">🐬 MySQL</option>
                                    <option value="docker">🐳 Docker</option>
                                    <option value="other">⚙️ Otro</option>
                                </select>
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Puerto</label>
                                <Input
                                    name="port"
                                    type="number"
                                    placeholder="8069"
                                    value={formData.port}
                                    onChange={handleInputChange}
                                    className="rounded-xl border-2"
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium flex items-center gap-1">
                                    <Server size={14} /> VPS Asociado
                                </label>
                                <select
                                    name="vpsId"
                                    value={formData.vpsId}
                                    onChange={handleInputChange}
                                    className="w-full px-3 py-2 rounded-xl border-2 border-gray-200 focus:border-violet-300 focus:outline-none bg-white"
                                >
                                    <option value="">Sin VPS</option>
                                    {vpsList.map(vps => (
                                        <option key={vps.id} value={vps.id}>
                                            {vps.name} ({vps.ipAddress || "Sin IP"})
                                        </option>
                                    ))}
                                </select>
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Estado Inicial</label>
                                <select
                                    name="status"
                                    value={formData.status}
                                    onChange={handleInputChange}
                                    className="w-full px-3 py-2 rounded-xl border-2 border-gray-200 focus:border-violet-300 focus:outline-none bg-white"
                                >
                                    <option value="running">Ejecutando</option>
                                    <option value="stopped">Detenido</option>
                                </select>
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm font-medium flex items-center gap-1">
                                <Globe size={14} /> URL de Acceso
                            </label>
                            <Input
                                name="url"
                                placeholder="https://app.ejemplo.com"
                                value={formData.url}
                                onChange={handleInputChange}
                                className="rounded-xl border-2"
                            />
                        </div>

                        <DialogFooter>
                            <Button
                                type="button"
                                variant="outline"
                                onClick={() => setIsModalOpen(false)}
                                className="rounded-xl"
                            >
                                Cancelar
                            </Button>
                            <Button
                                type="submit"
                                disabled={isSubmitting}
                                className="rounded-xl bg-gradient-to-r from-violet-500 to-purple-600"
                            >
                                {isSubmitting ? (
                                    <RotateCw className="w-4 h-4 animate-spin mr-2" />
                                ) : (
                                    <Plus className="w-4 h-4 mr-2" />
                                )}
                                Crear Servicio
                            </Button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import {
    Settings, Save, Mail, Key, Bell, Server, RefreshCw,
    CheckCircle, AlertTriangle, Eye, EyeOff, Shield, Database, Download, Upload, HardDrive
} from "lucide-react";
import { useToast } from "@/components/ui/toast";
import BackupPanel from "@/components/BackupPanel";

interface SettingsSection {
    id: string;
    title: string;
    icon: React.ElementType;
    description: string;
    fields: SettingsField[];
}

interface SettingsField {
    key: string;
    label: string;
    type: "text" | "password" | "number" | "email";
    placeholder?: string;
    description?: string;
}

const SETTINGS_SECTIONS: SettingsSection[] = [
    {
        id: "smtp",
        title: "Email (SMTP)",
        icon: Mail,
        description: "Configuración para enviar notificaciones por email",
        fields: [
            { key: "smtp_host", label: "Host SMTP", type: "text", placeholder: "smtp.gmail.com" },
            { key: "smtp_port", label: "Puerto", type: "number", placeholder: "587" },
            { key: "smtp_user", label: "Usuario", type: "email", placeholder: "tu@email.com" },
            { key: "smtp_pass", label: "Contraseña", type: "password", placeholder: "••••••••" },
            { key: "alert_email", label: "Email de alertas", type: "email", placeholder: "admin@tuempresa.com", description: "Recibe alertas de pagos y recursos" },
        ],
    },
    {
        id: "api",
        title: "API Tokens",
        icon: Key,
        description: "Tokens de acceso para integraciones",
        fields: [
            { key: "hostinger_token", label: "Hostinger API Token", type: "password", placeholder: "Bearer token..." },
            { key: "odoo_url", label: "Odoo URL", type: "text", placeholder: "https://odoo.tuempresa.com" },
            { key: "odoo_db", label: "Odoo Database", type: "text", placeholder: "production" },
            { key: "odoo_user", label: "Odoo Usuario", type: "text", placeholder: "admin" },
            { key: "odoo_key", label: "Odoo API Key", type: "password", placeholder: "API key..." },
        ],
    },
    {
        id: "alerts",
        title: "Umbrales de Alertas",
        icon: Bell,
        description: "Configurar cuándo se generan alertas de recursos",
        fields: [
            { key: "alert_cpu_warning", label: "CPU Warning (%)", type: "number", placeholder: "70" },
            { key: "alert_cpu_critical", label: "CPU Critical (%)", type: "number", placeholder: "90" },
            { key: "alert_ram_warning", label: "RAM Warning (%)", type: "number", placeholder: "80" },
            { key: "alert_ram_critical", label: "RAM Critical (%)", type: "number", placeholder: "95" },
            { key: "alert_disk_warning", label: "Disco Warning (%)", type: "number", placeholder: "85" },
            { key: "alert_disk_critical", label: "Disco Critical (%)", type: "number", placeholder: "95" },
        ],
    },
    {
        id: "security",
        title: "Seguridad",
        icon: Shield,
        description: "Configuración de seguridad de la aplicación",
        fields: [
            { key: "master_password", label: "Master Password", type: "password", placeholder: "Contraseña maestra" },
            { key: "session_timeout", label: "Timeout de sesión (min)", type: "number", placeholder: "60" },
        ],
    },
    {
        id: "backup",
        title: "Backups",
        icon: Database,
        description: "Credenciales SSH para respaldos de datos",
        fields: [
            { key: "backup_host", label: "Host", type: "text", placeholder: "127.0.0.1" },
            { key: "backup_port", label: "Puerto", type: "number", placeholder: "22" },
            { key: "backup_user", label: "Usuario SSH", type: "text", placeholder: "root" },
        ],
    },
];

export default function SettingsPage() {
    const { toast } = useToast();
    const [settings, setSettings] = useState<Record<string, string>>({});
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [showPasswords, setShowPasswords] = useState<Record<string, boolean>>({});
    const [smtpStatus, setSmtpStatus] = useState<"unknown" | "ok" | "error">("unknown");
    const [backupPassword, setBackupPassword] = useState<string | null>(null);
    const [exporting, setExporting] = useState(false);
    const [importing, setImporting] = useState(false);

    useEffect(() => {
        fetchSettings();
        checkSmtpStatus();
    }, []);

    const fetchSettings = async () => {
        try {
            const res = await fetch("/api/settings");
            const data = await res.json();
            if (data.success) {
                setSettings(data.data || {});
            }
        } catch (err) {
            console.error("Error fetching settings:", err);
        } finally {
            setLoading(false);
        }
    };

    const checkSmtpStatus = async () => {
        try {
            const res = await fetch("/api/email");
            const data = await res.json();
            setSmtpStatus(data.success ? "ok" : "error");
        } catch {
            setSmtpStatus("error");
        }
    };

    const saveSettings = async () => {
        setSaving(true);
        try {
            const res = await fetch("/api/settings", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ settings }),
            });
            const data = await res.json();

            if (data.success) {
                toast({ title: "✅ Configuración guardada", description: "Los cambios se aplicarán inmediatamente" });
                checkSmtpStatus();
            } else {
                toast({ title: "Error", description: data.error, variant: "destructive" });
            }
        } catch (err) {
            toast({ title: "Error", description: "No se pudo guardar", variant: "destructive" });
        } finally {
            setSaving(false);
        }
    };

    const updateSetting = (key: string, value: string) => {
        setSettings(prev => ({ ...prev, [key]: value }));
    };

    const togglePassword = (key: string) => {
        setShowPasswords(prev => ({ ...prev, [key]: !prev[key] }));
    };

    const requestBackupPassword = async (): Promise<string | null> => {
        if (backupPassword) return backupPassword;
        const pwd = window.prompt("Contraseña SSH:");
        if (pwd) setBackupPassword(pwd);
        return pwd;
    };

    const handleExport = async () => {
        setExporting(true);
        try {
            const res = await fetch("/api/system/export");
            const blob = await res.blob();
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement("a");
            a.href = url;
            a.download = `rnv-backup-${new Date().toISOString().split("T")[0]}.json`;
            document.body.appendChild(a);
            a.click();
            window.URL.revokeObjectURL(url);
            toast({ title: "✅ Exportación completada", description: "El archivo se ha descargado correctamente" });
        } catch (err) {
            console.error(err);
            toast({ title: "Error", description: "Falló la exportación", variant: "destructive" });
        } finally {
            setExporting(false);
        }
    };

    const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!confirm("⚠️ ADVERTENCIA: Esta acción reemplazará TODOS los datos actuales con los del respaldo. ¿Estás seguro de continuar?")) {
            e.target.value = "";
            return;
        }

        setImporting(true);
        try {
            const content = await file.text();
            const json = JSON.parse(content);

            const res = await fetch("/api/system/import", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(json),
            });

            const data = await res.json();
            if (data.success) {
                toast({ title: "✅ Restauración exitosa", description: "Los datos han sido restaurados. Recarga la página." });
                setTimeout(() => window.location.reload(), 2000);
            } else {
                toast({ title: "Error", description: data.error || "Falló la importación", variant: "destructive" });
            }
        } catch (err) {
            console.error(err);
            toast({ title: "Error", description: "Archivo de respaldo inválido", variant: "destructive" });
        } finally {
            setImporting(false);
            e.target.value = "";
        }
    };

    const backupHost = settings.backup_host || "";
    const backupUser = settings.backup_user || "";
    const backupPort = parseInt(settings.backup_port || "22", 10) || 22;
    const backupReady = Boolean(backupHost && backupUser);

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[400px]">
                <RefreshCw className="w-8 h-8 text-violet-500 animate-spin" />
            </div>
        );
    }

    return (
        <div className="space-y-8">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold text-white">Configuración</h1>
                    <p className="text-gray-400 mt-1">Gestiona las preferencias y conexiones de la aplicación</p>
                </div>
                <button
                    onClick={saveSettings}
                    disabled={saving}
                    className="px-6 py-3 bg-violet-600 hover:bg-violet-700 disabled:bg-gray-600 text-white font-medium rounded-xl transition flex items-center gap-2"
                >
                    {saving ? (
                        <RefreshCw className="w-5 h-5 animate-spin" />
                    ) : (
                        <Save className="w-5 h-5" />
                    )}
                    Guardar Cambios
                </button>
            </div>

            {/* SMTP Status Banner */}
            <div className={`p-4 rounded-xl border ${smtpStatus === "ok"
                    ? "bg-green-900/30 border-green-700"
                    : smtpStatus === "error"
                        ? "bg-red-900/30 border-red-700"
                        : "bg-gray-800 border-gray-700"
                }`}>
                <div className="flex items-center gap-3">
                    {smtpStatus === "ok" ? (
                        <CheckCircle className="w-5 h-5 text-green-400" />
                    ) : smtpStatus === "error" ? (
                        <AlertTriangle className="w-5 h-5 text-red-400" />
                    ) : (
                        <Mail className="w-5 h-5 text-gray-400" />
                    )}
                    <div>
                        <p className={`font-medium ${smtpStatus === "ok" ? "text-green-300" :
                                smtpStatus === "error" ? "text-red-300" : "text-gray-300"
                            }`}>
                            {smtpStatus === "ok" ? "Email configurado y funcionando" :
                                smtpStatus === "error" ? "Email no configurado o con errores" :
                                    "Verificando configuración de email..."}
                        </p>
                        <p className="text-sm text-gray-500">
                            {smtpStatus === "error" && "Configura SMTP para recibir alertas por email"}
                        </p>
                    </div>
                </div>
            </div>

            {/* Settings Sections */}
            <div className="grid gap-6">
                {SETTINGS_SECTIONS.map((section) => (
                    <div key={section.id} className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
                        <div className="px-6 py-4 bg-gray-900 border-b border-gray-700 flex items-center gap-3">
                            <section.icon className="w-5 h-5 text-violet-400" />
                            <div>
                                <h2 className="font-bold text-white">{section.title}</h2>
                                <p className="text-sm text-gray-500">{section.description}</p>
                            </div>
                        </div>
                        <div className="p-6 grid gap-4 md:grid-cols-2">
                            {section.fields.map((field) => (
                                <div key={field.key} className="space-y-1">
                                    <label className="text-sm font-medium text-gray-300">
                                        {field.label}
                                    </label>
                                    <div className="relative">
                                        <input
                                            type={field.type === "password" && !showPasswords[field.key] ? "password" : field.type === "password" ? "text" : field.type}
                                            value={settings[field.key] || ""}
                                            onChange={(e) => updateSetting(field.key, e.target.value)}
                                            placeholder={field.placeholder}
                                            className="w-full px-4 py-2.5 bg-gray-700 border border-gray-600 rounded-lg text-white placeholder-gray-500 focus:border-violet-500 focus:outline-none pr-10"
                                        />
                                        {field.type === "password" && (
                                            <button
                                                type="button"
                                                onClick={() => togglePassword(field.key)}
                                                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-white"
                                            >
                                                {showPasswords[field.key] ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                            </button>
                                        )}
                                    </div>
                                    {field.description && (
                                        <p className="text-xs text-gray-500">{field.description}</p>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                ))}
            </div>

            <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
                <div className="px-6 py-4 bg-gray-900 border-b border-gray-700 flex items-center gap-3">
                    <HardDrive className="w-5 h-5 text-cyan-400" />
                    <div>
                        <h2 className="font-bold text-white">Gestión de Datos Locales</h2>
                        <p className="text-sm text-gray-500">Exportar e importar datos de la aplicación para migración</p>
                    </div>
                </div>
                <div className="p-6">
                    <div className="flex flex-col md:flex-row gap-4">
                        <button
                            onClick={handleExport}
                            disabled={exporting}
                            className="flex-1 bg-cyan-600/20 hover:bg-cyan-600/30 border border-cyan-500/30 text-cyan-200 px-6 py-4 rounded-xl flex items-center justify-center gap-3 transition"
                        >
                            {exporting ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                            <div className="text-left">
                                <span className="block font-bold">Exportar Datos</span>
                                <span className="text-xs opacity-70">Descargar JSON completo</span>
                            </div>
                        </button>

                        <div className="flex-1 relative">
                            <input
                                type="file"
                                accept=".json"
                                onChange={handleImport}
                                disabled={importing}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                            />
                            <div className="bg-orange-600/20 hover:bg-orange-600/30 border border-orange-500/30 text-orange-200 px-6 py-4 rounded-xl flex items-center justify-center gap-3 transition h-full">
                                {importing ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Upload className="w-5 h-5" />}
                                <div className="text-left">
                                    <span className="block font-bold">Importar Datos</span>
                                    <span className="text-xs opacity-70">Restaurar desde JSON</span>
                                </div>
                            </div>
                        </div>
                    </div>
                    <p className="text-xs text-gray-500 mt-4 text-center">
                        ⚠️ La importación reemplazará todos los datos actuales. Asegúrate de tener un respaldo reciente.
                    </p>
                </div>
            </div>

            <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
                <div className="px-6 py-4 bg-gray-900 border-b border-gray-700 flex items-center gap-3">
                    <Database className="w-5 h-5 text-violet-400" />
                    <div>
                        <h2 className="font-bold text-white">Backup de datos</h2>
                        <p className="text-sm text-gray-500">Genera respaldos desde el servidor configurado</p>
                    </div>
                </div>
                <div className="p-6 space-y-4">
                    {!backupReady && (
                        <div className="text-sm text-yellow-300">
                            Completa Host y Usuario SSH en la sección de Backups para habilitar el respaldo.
                        </div>
                    )}
                    {backupReady && (
                        <BackupPanel
                            host={backupHost}
                            port={backupPort}
                            username={backupUser}
                            onPasswordRequest={requestBackupPassword}
                        />
                    )}
                </div>
            </div>

            {/* Info */}
            <div className="bg-gray-800/50 rounded-xl p-4 border border-gray-700">
                <div className="flex items-start gap-3">
                    <Server className="w-5 h-5 text-cyan-400 mt-0.5" />
                    <div>
                        <p className="text-sm text-gray-300 font-medium">Configuración almacenada en base de datos</p>
                        <p className="text-xs text-gray-500 mt-1">
                            Los cambios se guardan en la tabla <code className="bg-gray-700 px-1 rounded">AppSettings</code>
                            y están disponibles para todas las instancias de la aplicación.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import dynamic from "next/dynamic";
import { Terminal, Download, Activity } from "lucide-react";

const SSHConsole = dynamic(() => import("@/components/SSHConsole"), { ssr: false });
const ServerMonitor = dynamic(() => import("@/components/ServerMonitor"), { ssr: false });
const BackupPanel = dynamic(() => import("@/components/BackupPanel"), { ssr: false });

interface Service {
    id: string;
    name: string;
    type: string;
    port?: number;
    url?: string;
    configFile?: string;
    monthlyCost: number;
    status: string;
    client?: { id: string; name: string } | null;
}

interface VPS {
    id: string;
    name: string;
    ipAddress: string;
    provider: string;
    hostingerId?: string;
    status: string;
    monthlyCost: number;
    sshUser: string;
    sshPort: number;
    client?: { id: string; name: string; email?: string } | null;
    services: Service[];
    totalServiceCost?: number;
    totalMonthlyCost?: number;
}

interface Client {
    id: string;
    name: string;
}

export default function VPSDetailPage() {
    const params = useParams();
    const router = useRouter();
    const vpsId = params.id as string;

    const [vps, setVps] = useState<VPS | null>(null);
    const [clients, setClients] = useState<Client[]>([]);
    const [loading, setLoading] = useState(true);
    const [editing, setEditing] = useState(false);
    const [showAddService, setShowAddService] = useState(false);
    const [showTerminal, setShowTerminal] = useState(false);
    const [showMonitor, setShowMonitor] = useState(false);
    const [showBackup, setShowBackup] = useState(false);
    const [sshPassword, setSshPassword] = useState<string | null>(null);

    // Password prompt for SSH operations
    const requestPassword = async (): Promise<string | null> => {
        if (sshPassword) return sshPassword;
        const pwd = window.prompt("Contraseña SSH:");
        if (pwd) setSshPassword(pwd);
        return pwd;
    };

    // Edit form state
    const [editForm, setEditForm] = useState({
        name: "",
        monthlyCost: 0,
        clientId: "",
    });

    // New service form
    const [newService, setNewService] = useState({
        name: "",
        type: "odoo",
        url: "",
        port: 0,
        monthlyCost: 0,
        configFile: "",
    });

    useEffect(() => {
        fetchVPS();
        fetchClients();
    }, [vpsId]);

    const fetchVPS = async () => {
        try {
            const res = await fetch(`/api/vps/${vpsId}`);
            const data = await res.json();
            if (data.success) {
                setVps(data.data);
                setEditForm({
                    name: data.data.name,
                    monthlyCost: data.data.monthlyCost || 0,
                    clientId: data.data.client?.id || "",
                });
            }
        } catch (err) {
            console.error("Error fetching VPS:", err);
        } finally {
            setLoading(false);
        }
    };

    const fetchClients = async () => {
        try {
            const res = await fetch("/api/clients");
            const data = await res.json();
            if (data.success) {
                setClients(data.data);
            }
        } catch (err) {
            console.error("Error fetching clients:", err);
        }
    };

    const handleSaveVPS = async () => {
        try {
            const res = await fetch(`/api/vps/${vpsId}`, {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(editForm),
            });
            const data = await res.json();
            if (data.success) {
                setVps(data.data);
                setEditing(false);
                fetchVPS(); // Reload to get updated relations
            }
        } catch (err) {
            console.error("Error saving VPS:", err);
        }
    };

    const handleAddService = async () => {
        try {
            const res = await fetch(`/api/vps/${vpsId}/services`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    ...newService,
                    url: newService.url || `https://${newService.name}.renace.tech`,
                }),
            });
            const data = await res.json();
            if (data.success) {
                setShowAddService(false);
                setNewService({ name: "", type: "odoo", url: "", port: 0, monthlyCost: 0, configFile: "" });
                fetchVPS();
            }
        } catch (err) {
            console.error("Error adding service:", err);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-900 text-white p-8 flex items-center justify-center">
                <div className="animate-spin rounded-full h-12 w-12 border-4 border-cyan-500 border-t-transparent"></div>
            </div>
        );
    }

    if (!vps) {
        return (
            <div className="min-h-screen bg-gray-900 text-white p-8">
                <p>VPS not found</p>
                <Link href="/vps" className="text-cyan-400 hover:underline">← Back to VPS list</Link>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-900 text-white p-8">
            {/* Header */}
            <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-4">
                    <Link href="/vps" className="text-gray-400 hover:text-white">
                        ← Back
                    </Link>
                    <h1 className="text-3xl font-bold">{vps.name}</h1>
                    <span className={`px-3 py-1 rounded-full text-sm ${vps.status === "running" ? "bg-green-500/20 text-green-400" :
                        vps.status === "stopped" ? "bg-red-500/20 text-red-400" :
                            "bg-yellow-500/20 text-yellow-400"
                        }`}>
                        {vps.status}
                    </span>
                </div>
                <div className="flex flex-wrap gap-2">
                    <button
                        onClick={() => setShowTerminal(!showTerminal)}
                        className="px-4 py-2 bg-green-600 hover:bg-green-700 rounded-lg transition flex items-center gap-2"
                    >
                        <Terminal className="w-4 h-4" />
                        {showTerminal ? "Cerrar" : "Terminal"}
                    </button>
                    <button
                        onClick={() => setShowMonitor(!showMonitor)}
                        className="px-4 py-2 bg-purple-600 hover:bg-purple-700 rounded-lg transition flex items-center gap-2"
                    >
                        <Activity className="w-4 h-4" />
                        {showMonitor ? "Cerrar" : "Monitor"}
                    </button>
                    <button
                        onClick={() => setShowBackup(!showBackup)}
                        className="px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg transition flex items-center gap-2"
                    >
                        <Download className="w-4 h-4" />
                        {showBackup ? "Cerrar" : "Backup"}
                    </button>
                    <button
                        onClick={() => setEditing(!editing)}
                        className="px-4 py-2 bg-cyan-600 hover:bg-cyan-700 rounded-lg transition"
                    >
                        {editing ? "Cancel" : "Edit VPS"}
                    </button>
                </div>
            </div>

            {/* SSH Terminal */}
            {showTerminal && (
                <div className="mb-6">
                    <SSHConsole
                        host={vps.ipAddress}
                        port={vps.sshPort || 22}
                        username={vps.sshUser || "root"}
                        onClose={() => setShowTerminal(false)}
                    />
                </div>
            )}

            {/* Server Monitor */}
            {showMonitor && (
                <div className="mb-6">
                    <ServerMonitor
                        host={vps.ipAddress}
                        port={vps.sshPort || 22}
                        username={vps.sshUser || "root"}
                        onPasswordRequest={requestPassword}
                    />
                </div>
            )}

            {/* Backup Panel */}
            {showBackup && (
                <div className="mb-6">
                    <BackupPanel
                        host={vps.ipAddress}
                        port={vps.sshPort || 22}
                        username={vps.sshUser || "root"}
                        onPasswordRequest={requestPassword}
                    />
                </div>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* VPS Info Card */}
                <div className="bg-gray-800 rounded-xl p-6 border border-gray-700">
                    <h2 className="text-xl font-semibold mb-4">VPS Information</h2>

                    {editing ? (
                        <div className="space-y-4">
                            <div>
                                <label className="text-sm text-gray-400">Name</label>
                                <input
                                    type="text"
                                    value={editForm.name}
                                    onChange={(e) => setEditForm({ ...editForm, name: e.target.value })}
                                    className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                />
                            </div>
                            <div>
                                <label className="text-sm text-gray-400">Monthly Cost ($)</label>
                                <input
                                    type="number"
                                    value={editForm.monthlyCost}
                                    onChange={(e) => setEditForm({ ...editForm, monthlyCost: parseFloat(e.target.value) || 0 })}
                                    className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                />
                            </div>
                            <div>
                                <label className="text-sm text-gray-400">Assign to Client</label>
                                <select
                                    value={editForm.clientId}
                                    onChange={(e) => setEditForm({ ...editForm, clientId: e.target.value })}
                                    className="w-full mt-1 px-3 py-2 bg-gray-700 rounded-lg border border-gray-600 focus:border-cyan-500 focus:outline-none"
                                >
                                    <option value="">-- No Client --</option>
                                    {clients.map((c) => (
                                        <option key={c.id} value={c.id}>{c.name}</option>
                                    ))}
                                </select>
                            </div>
                            <button
                                onClick={handleSaveVPS}
                                className="w-full py-2 bg-green-600 hover:bg-green-700 rounded-lg transition"
                            >
                                Save Changes
                            </button>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            <div className="flex justify-between">
                                <span className="text-gray-400">IP Address</span>
                                <span className="font-mono text-cyan-400">{vps.ipAddress}</span>
                            </div>
                            <div className="flex justify-between">
                                <span className="text-gray-400">Provider</span>
                                <span>{vps.provider}</span>
                            </div>
                            <div className="flex justify-between">
                                <span className="text-gray-400">SSH</span>
                                <span className="font-mono">{vps.sshUser}@{vps.ipAddress}:{vps.sshPort}</span>
                            </div>
                            <div className="flex justify-between">
                                <span className="text-gray-400">Hostinger ID</span>
                                <span className="font-mono text-sm">{vps.hostingerId || "N/A"}</span>
                            </div>
                            <hr className="border-gray-700 my-4" />
                            <div className="flex justify-between">
                                <span className="text-gray-400">VPS Cost</span>
                                <span className="text-green-400">${vps.monthlyCost}/mo</span>
                            </div>
                            <div className="flex justify-between">
                                <span className="text-gray-400">Services Cost</span>
                                <span className="text-green-400">${vps.totalServiceCost || 0}/mo</span>
                            </div>
                            <div className="flex justify-between font-bold">
                                <span>Total</span>
                                <span className="text-green-400">${vps.totalMonthlyCost || vps.monthlyCost}/mo</span>
                            </div>
                            <hr className="border-gray-700 my-4" />
                            <div className="flex justify-between">
                                <span className="text-gray-400">Client</span>
                                {vps.client ? (
                                    <Link href={`/clients/${vps.client.id}`} className="text-cyan-400 hover:underline">
                                        {vps.client.name}
                                    </Link>
                                ) : (
                                    <span className="text-yellow-400">Not assigned</span>
                                )}
                            </div>
                        </div>
                    )}
                </div>

                {/* Services List */}
                <div className="lg:col-span-2 bg-gray-800 rounded-xl p-6 border border-gray-700">
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="text-xl font-semibold">Services ({vps.services?.length || 0})</h2>
                        <button
                            onClick={() => setShowAddService(!showAddService)}
                            className="px-4 py-2 bg-cyan-600 hover:bg-cyan-700 rounded-lg transition text-sm"
                        >
                            {showAddService ? "Cancel" : "+ Add Service"}
                        </button>
                    </div>

                    {/* Add Service Form */}
                    {showAddService && (
                        <div className="bg-gray-700 rounded-lg p-4 mb-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm text-gray-400">Subdomain Name</label>
                                    <input
                                        type="text"
                                        placeholder="e.g., myapp"
                                        value={newService.name}
                                        onChange={(e) => setNewService({ ...newService, name: e.target.value })}
                                        className="w-full mt-1 px-3 py-2 bg-gray-600 rounded-lg border border-gray-500 focus:border-cyan-500 focus:outline-none"
                                    />
                                    <p className="text-xs text-gray-500 mt-1">→ {newService.name || "subdomain"}.renace.tech</p>
                                </div>
                                <div>
                                    <label className="text-sm text-gray-400">Type</label>
                                    <select
                                        value={newService.type}
                                        onChange={(e) => setNewService({ ...newService, type: e.target.value })}
                                        className="w-full mt-1 px-3 py-2 bg-gray-600 rounded-lg border border-gray-500 focus:border-cyan-500 focus:outline-none"
                                    >
                                        <option value="odoo">Odoo</option>
                                        <option value="web">Web</option>
                                        <option value="api">API</option>
                                        <option value="database">Database</option>
                                        <option value="storage">Storage</option>
                                        <option value="ai">AI</option>
                                        <option value="other">Other</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="text-sm text-gray-400">Port (optional)</label>
                                    <input
                                        type="number"
                                        value={newService.port || ""}
                                        onChange={(e) => setNewService({ ...newService, port: parseInt(e.target.value) || 0 })}
                                        className="w-full mt-1 px-3 py-2 bg-gray-600 rounded-lg border border-gray-500 focus:border-cyan-500 focus:outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="text-sm text-gray-400">Monthly Cost ($)</label>
                                    <input
                                        type="number"
                                        value={newService.monthlyCost || ""}
                                        onChange={(e) => setNewService({ ...newService, monthlyCost: parseFloat(e.target.value) || 0 })}
                                        className="w-full mt-1 px-3 py-2 bg-gray-600 rounded-lg border border-gray-500 focus:border-cyan-500 focus:outline-none"
                                    />
                                </div>
                                <div className="col-span-2">
                                    <label className="text-sm text-gray-400">Config File Path (optional)</label>
                                    <input
                                        type="text"
                                        placeholder="/etc/nginx/sites-available/..."
                                        value={newService.configFile}
                                        onChange={(e) => setNewService({ ...newService, configFile: e.target.value })}
                                        className="w-full mt-1 px-3 py-2 bg-gray-600 rounded-lg border border-gray-500 focus:border-cyan-500 focus:outline-none"
                                    />
                                </div>
                            </div>
                            <button
                                onClick={handleAddService}
                                className="mt-4 w-full py-2 bg-green-600 hover:bg-green-700 rounded-lg transition"
                            >
                                Create Service
                            </button>
                        </div>
                    )}

                    {/* Services Grid */}
                    <div className="grid gap-4">
                        {vps.services?.length === 0 ? (
                            <p className="text-gray-500 text-center py-8">No services configured</p>
                        ) : (
                            vps.services?.map((service) => (
                                <div key={service.id} className="bg-gray-700/50 rounded-lg p-4 border border-gray-600 hover:border-cyan-500/50 transition">
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <div className="flex items-center gap-2">
                                                <Link
                                                    href={`/services/${service.id}`}
                                                    className="text-lg font-semibold text-cyan-400 hover:underline"
                                                >
                                                    {service.name}
                                                </Link>
                                                <span className={`px-2 py-0.5 text-xs rounded-full ${service.type === "odoo" ? "bg-purple-500/20 text-purple-400" :
                                                    service.type === "web" ? "bg-blue-500/20 text-blue-400" :
                                                        service.type === "api" ? "bg-orange-500/20 text-orange-400" :
                                                            "bg-gray-500/20 text-gray-400"
                                                    }`}>
                                                    {service.type}
                                                </span>
                                            </div>
                                            {service.url && (
                                                <a
                                                    href={service.url}
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    className="text-sm text-gray-400 hover:text-cyan-400 flex items-center gap-1 mt-1"
                                                >
                                                    🔗 {service.url}
                                                </a>
                                            )}
                                            {service.configFile && (
                                                <p className="text-xs text-gray-500 mt-1 font-mono">📄 {service.configFile}</p>
                                            )}
                                        </div>
                                        <div className="text-right">
                                            <p className="text-green-400 font-semibold">${service.monthlyCost}/mo</p>
                                            {service.client ? (
                                                <p className="text-xs text-gray-400">→ {service.client.name}</p>
                                            ) : (
                                                <p className="text-xs text-yellow-400">No client</p>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/components/ui/toast";
import { Server, Plus, Search, RefreshCw, Copy, MoreHorizontal, Check, AlertCircle, Clock, Zap, Terminal, Power, ExternalLink } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback } from "react";

interface VPSItem {
    id: string;
    name: string;
    ipAddress: string;
    provider: string;
    status: string;
    plan?: string;
    datacenter?: string;
}

export default function VPSPage() {
    const [vpsList, setVpsList] = useState<VPSItem[]>([]);
    const [filteredList, setFilteredList] = useState<VPSItem[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [copiedId, setCopiedId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState("");
    const [lastSync, setLastSync] = useState<Date | null>(null);
    const { addToast } = useToast();

    const fetchVPS = useCallback(async (forceRefresh = false) => {
        setIsLoading(true);
        setError(null);

        try {
            const url = forceRefresh ? "/api/hostinger/vps?refresh=true" : "/api/hostinger/vps";
            const res = await fetch(url);
            const data = await res.json();

            if (data.success && data.data) {
                setVpsList(data.data);
                setFilteredList(data.data);
                setLastSync(new Date());
                addToast(`${data.data.length} servidores cargados`, "success");
            } else {
                setError(data.error);
                addToast(data.error || "Error al cargar", "error");
            }
        } catch (err: any) {
            setError(err.message);
            addToast("Error de conexión", "error");
        } finally {
            setIsLoading(false);
        }
    }, [addToast]);

    useEffect(() => {
        fetchVPS();
    }, [fetchVPS]);

    useEffect(() => {
        if (searchTerm) {
            setFilteredList(vpsList.filter(vps =>
                vps.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                vps.ipAddress.includes(searchTerm)
            ));
        } else {
            setFilteredList(vpsList);
        }
    }, [searchTerm, vpsList]);

    const copyIP = (ip: string, id: string) => {
        navigator.clipboard.writeText(ip);
        setCopiedId(id);
        addToast("IP copiada", "success", 2000);
        setTimeout(() => setCopiedId(null), 2000);
    };

    const runningCount = vpsList.filter(v => v.status === "running").length;

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold text-gray-900">Servidores VPS</h1>
                    <p className="text-gray-500 mt-1">
                        {isLoading ? "Cargando..." : `${vpsList.length} servidores • ${runningCount} activos`}
                    </p>
                </div>
