    const [pos, setPos] = useState({ x: 0, y: 0 });
    const [dragging, setDragging] = useState(false);
    const dragOffset = useRef({ x: 0, y: 0 });
    const dragStartPos = useRef({ x: 0, y: 0 });

    const inputRef = useRef<HTMLInputElement>(null);
    const scrollRef = useRef<HTMLDivElement>(null);

    const genId = () => Math.random().toString(36).substring(2, 10);

    // Initialize position to bottom-right
    useEffect(() => {
        if (isWidget) {
            // Widget mode is fixed relative to its own window
            setPos({ x: 20, y: 20 });
            // Let the widget open natively if we are a widget
            setIsOpen(true);
        } else {
            setPos({
                x: window.innerWidth - 80,
                y: window.innerHeight - 80,
            });
        }
    }, [isWidget]);

    // Auto-scroll floating messages
    useEffect(() => {
        scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: "smooth" });
    }, [messages]);

    // Focus input when opened
    useEffect(() => {
        if (isOpen) setTimeout(() => inputRef.current?.focus(), 100);
    }, [isOpen]);

    // External open event
    useEffect(() => {
        const handleOpen = () => setIsOpen(true);
        window.addEventListener("rnv-ai-open", handleOpen);
        return () => window.removeEventListener("rnv-ai-open", handleOpen);
    }, []);

    // Hydrate from localStorage
    useEffect(() => {
        const saved = localStorage.getItem("rnv_ai_history");
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                const restored = parsed.map((m: any) => ({
                    ...m,
                    timestamp: new Date(m.timestamp)
                }));
                if (restored.length > 0) {
                    setMessages(restored);
                }
            } catch (e) {
                console.error("Failed to parse AI history", e);
            }
        }
        setIsHydrated(true);
    }, []);

    // Welcome message if no history
    useEffect(() => {
        if (isHydrated && messages.length === 0) {
            setMessages([{
                id: genId(),
                role: "assistant",
                content: "¡Hola! 🎉 Soy tu asistente **RNV**. Dime qué necesitas y lo materializo al instante.\n\n:::quick-actions\nVer clientes activos\nResumen financiero\nRegistrar un pago\nListar servidores VPS\nVer calendario\nConfigurar correo\n:::",
                timestamp: new Date()
            }]);
        }
    }, [isHydrated, messages.length]);

    // Save to localStorage when messages change
    useEffect(() => {
        if (isHydrated && messages.length > 0) {
            // Keep the last 15 messages so it doesn't get too heavy
            const toSave = messages.slice(-15);
            localStorage.setItem("rnv_ai_history", JSON.stringify(toSave));
        }
    }, [messages, isHydrated]);

    // Wipe memory
    const wipeMemory = useCallback(() => {
        localStorage.removeItem("rnv_ai_history");
        setMessages([{
            id: genId(),
            role: "assistant",
            content: "🧹 Memoria borrada. ¡Comencemos de nuevo!",
            timestamp: new Date()
        }]);
    }, []);

    // Toolbar mode detection: if dragged to top edge
    useEffect(() => {
        setIsToolbarMode(pos.y < 60);
    }, [pos.y]);

    /* ═══════════════ DRAG HANDLERS (pointer events) ═══════════════ */

    const handlePointerDown = useCallback((e: React.PointerEvent) => {
        if (isWidget) return; // Let Electron handle dragging natively via -webkit-app-region
        e.preventDefault();
        e.stopPropagation();
        setDragging(true);
        dragStartPos.current = { x: e.clientX, y: e.clientY };
        dragOffset.current = {
            x: e.clientX - pos.x,
            y: e.clientY - pos.y,
        };
        (e.target as HTMLElement).setPointerCapture(e.pointerId);
    }, [pos, isWidget]);

    const handlePointerMove = useCallback((e: React.PointerEvent) => {
        if (!dragging) return;
        e.preventDefault();
        const newX = Math.max(0, Math.min(window.innerWidth - 64, e.clientX - dragOffset.current.x));
        const newY = Math.max(0, Math.min(window.innerHeight - 64, e.clientY - dragOffset.current.y));
        setPos({ x: newX, y: newY });
    }, [dragging]);

    const handlePointerUp = useCallback((e: React.PointerEvent) => {
        setDragging(false);
        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
    }, []);

    const handleClick = useCallback((e: React.MouseEvent) => {
        // Calculate distance moved to differentiate tap from drag
        const dx = e.clientX - dragStartPos.current.x;
        const dy = e.clientY - dragStartPos.current.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        // If moved less than 10 pixels, consider it a tap/click
        if (distance < 10) {
            setIsOpen(prev => !prev);
        }
    }, []);

    /* ─────────────── Conversation handler ─────────────── */

    const sendMessage = useCallback(async (overrideMessage?: string) => {
        const text = overrideMessage || input.trim();
        if (!text || isLoading) return;

        const userMessage: Message = { id: genId(), role: "user", content: text, timestamp: new Date() };
        setMessages(prev => [...prev, userMessage]);
        if (!overrideMessage) setInput("");
        setIsLoading(true);
        setMascotState("thinking");
        // Auto-open to show response
        if (!isOpen) setIsOpen(true);

        try {
            const conversationHistory = messages.filter((m, idx) => {
                if (idx === 0 && m.role === "assistant" && !m.executedFunctions) return false;
                return true;
            });

            const response = await fetch("/api/ai/chat", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    message: text,
                    history: conversationHistory.map(m => ({ role: m.role, content: m.content })),
                    url: window.location.pathname
                })
            });

            const data = await response.json();

            if (data.success) {
                if (data.response.includes(":::animate\nbarrel-roll")) setMascotState("barrel-roll");
                else if (data.response.includes(":::animate\nshivering")) setMascotState("shivering");
                else if (data.response.includes(":::animate\ncelebrate")) setMascotState("celebrate");
                else setMascotState("success");

                setMessages(prev => [...prev, {
                    id: genId(),
                    role: "assistant",
                    content: data.response,
                    timestamp: new Date(),
                    executedFunctions: data.executedFunctions,
                }]);
            } else {
                throw new Error(data.error || "Error desconocido");
            }
        } catch (error: any) {
            console.error("AI Error:", error);
            setMascotState("error");
            setLastError(text); // Store for auto-fix retry
            let errorMsg = `❌ ${error.message}. Intenta de nuevo.`;
            if (error.message?.includes("429") || error.message?.includes("Quota")) {
                errorMsg = "⚠️ **Servicio saturado** — Espera un momento e inténtalo de nuevo.";
            }
            if (error.message?.includes("403") || error.message?.includes("GEMINI_API_KEY")) {
                errorMsg = "⚠️ **Asistente no configurado** — Configura GEMINI_API_KEY.";
            }
            errorMsg += "\n\n:::action-buttons\n🔄 Reintentar\n:::\n";
            setMessages(prev => [...prev, { id: genId(), role: "assistant", content: errorMsg, timestamp: new Date() }]);
        } finally {
            setIsLoading(false);
            setTimeout(() => setMascotState("idle"), 2500);
        }
    }, [input, isLoading, messages, isOpen]);

    // User message history for up/down recall
    const userMessages = useMemo(() => messages.filter(m => m.role === "user").map(m => m.content), [messages]);

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === "Enter" && !e.shiftKey) {
            e.preventDefault();
            setHistoryIndex(-1);
            sendMessage();
        }
        // Up arrow: recall previous user message
        if (e.key === "ArrowUp" && userMessages.length > 0) {
            e.preventDefault();
            const newIdx = Math.min(historyIndex + 1, userMessages.length - 1);
            setHistoryIndex(newIdx);
            setInput(userMessages[userMessages.length - 1 - newIdx]);
        }
        // Down arrow: recall more recent message
        if (e.key === "ArrowDown") {
            e.preventDefault();
            const newIdx = Math.max(historyIndex - 1, -1);
            setHistoryIndex(newIdx);
            setInput(newIdx >= 0 ? userMessages[userMessages.length - 1 - newIdx] : "");
        }
    };

    const handleAction = useCallback((cmd: string) => {
        // Handle auto-fix retry
        if (cmd === "🔄 Reintentar" && lastError) {
            sendMessage(lastError);
            setLastError(null);
        } else {
            sendMessage(cmd);
        }
    }, [sendMessage, lastError]);

    // Contextual suggestions based on current URL
    const contextualSuggestions = useMemo(() => {
        if (typeof window === "undefined") return [];
        const path = window.location.pathname;
        if (path.includes("/clients")) return ["Resumen de este cliente", "Registrar pago", "Ver servicios"];
        if (path.includes("/vps")) return ["Estado de este VPS", "Listar servicios", "Ver gastos"];
        if (path.includes("/services")) return ["Detalle del servicio", "Asignar cliente", "Ver costos"];
        if (path.includes("/payments")) return ["Pagos pendientes", "Resumen financiero", "Exportar reporte"];
        if (path === "/") return ["Resumen general", "Clientes activos", "Estado servidores"];
        return ["¿Qué puedo hacer?", "Resumen financiero"];
    }, []);

    /* ────────────── Message partitioning ──────────────── */

    const lastExchange = useMemo(() => {
        if (messages.length <= 3) return messages;
        return messages.slice(-3);
    }, [messages]);

    const olderMessages = useMemo(() => {
        if (messages.length <= 3) return [];
        return messages.slice(0, -3);
    }, [messages]);

    /* ──────────────── Render message ──────────────────── */

    const renderMessage = (msg: Message) => {
        if (msg.role === "user") {
            return (
                <motion.div
                    key={msg.id}
                    initial={{ opacity: 0, x: 10, scale: 0.9 }}
                    animate={{ opacity: 1, x: 0, scale: 1 }}
                    className="flex justify-end mb-2"
                >
                    <div className="max-w-[85%] bg-gradient-to-br from-violet-500/80 to-fuchsia-600/70 text-white
                                    rounded-2xl rounded-br-sm px-3 py-2 text-sm shadow-lg">
                        {msg.content}
                    </div>
                </motion.div>
            );
        }

        const blocks = parseRichBlocks(msg.content);

        return (
            <motion.div
                key={msg.id}
                initial={{ opacity: 0, y: 10, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                transition={{ type: "spring", damping: 20, stiffness: 200 }}
                className="mb-3 p-4 rounded-3xl rounded-bl-sm bg-black/60 backdrop-blur-2xl border border-violet-500/20 shadow-[0_8px_32px_rgba(0,0,0,0.5)] max-w-sm"
            >
                {blocks.map((block, bi) => {
                    switch (block.type) {
                        case "action-buttons":
                            return <ActionButtonsBlock key={bi} items={block.items || []} onAction={handleAction} />;
                        case "confirm":
                            return (
                                <ConfirmBlock
                                    key={bi}
                                    content={block.content}
                                    onConfirm={(pin) => {
                                        setPendingConfirm(null);
                                        const responseMsg = pin
                                            ? `Sí, confirmo: ${block.content}. El Maestro PIN ingresado es: ${pin}`
                                            : `Sí, confirmo: ${block.content}`;
                                        handleAction(responseMsg);
                                    }}
                                    onCancel={() => setPendingConfirm(null)}
                                />
                            );
                        case "summary-card":
                            return <SummaryCardBlock key={bi} items={block.items || []} />;
                        case "quick-actions":
                            return <QuickActionsBlock key={bi} items={block.items || []} onAction={handleAction} />;
                        case "navigate":
                            return <NavigateBlock key={bi} path={block.content} />;
                        case "metrics-chart":
                            return <MetricsChartBlock key={bi} content={block.content} />;
                        default:
                            return (
                                <div key={bi} className="prose prose-invert max-w-none prose-sm prose-p:leading-relaxed
                                    prose-pre:bg-black/60 prose-pre:text-cyan-100 prose-a:text-cyan-300
                                    prose-a:font-semibold hover:prose-a:no-underline
                                    prose-th:text-cyan-200 prose-th:bg-white/5 prose-td:border-cyan-500/10
                                    prose-table:border prose-table:border-cyan-500/20 prose-table:rounded-xl
                                    prose-th:px-3 prose-th:py-2 prose-td:px-3 prose-td:py-2 prose-th:text-left text-violet-50">
                                    <ReactMarkdown
                                        remarkPlugins={[remarkGfm]}
                                        urlTransform={(value: string) => value}
                                        components={{
                                            a: ({ ...props }) => {
                                                const href = props.href || "";
                                                if (href.startsWith("action:assign-service:")) {
                                                    const parts = href.split(":");
                                                    const serviceId = parts[2];
                                                    const clientName = decodeURIComponent(parts[3] || "");
                                                    const amount = parts[4] || "0";
                                                    return (
                                                        <button
                                                            onClick={(e) => {
                                                                e.preventDefault();
                                                                handleAction(`Asigna el servicio con ID "${serviceId}" a "${clientName}" por el monto de ${amount}`);
                                                            }}
                                                            className="action-btn-materialize inline-flex items-center gap-2 bg-violet-500/15
                                                                       hover:bg-violet-500/25 text-violet-200 font-semibold py-2 px-4
                                                                       rounded-xl text-xs border border-violet-400/40
                                                                       shadow-[0_0_14px_rgba(139,92,246,0.35)]
                                                                       hover:shadow-[0_0_24px_rgba(139,92,246,0.6)] transition-all my-1"
                                                        >
                                                            <ArrowRight className="w-3 h-3" />
                                                            {props.children}
                                                        </button>
                                                    );
                                                }
                                                return <a {...props} target="_blank" rel="noopener noreferrer" />;
                                            },
                                            table: ({ children }) => (
                                                <div className="overflow-x-auto my-2 rounded-xl border border-cyan-500/20">
                                                    <table className="w-full text-sm">{children}</table>
                                                </div>
                                            ),
                                        }}
                                    >
                                        {block.content}
                                    </ReactMarkdown>
                                </div>
                            );
                    }
                })}

                {/* Function execution badges */}
                {msg.executedFunctions && msg.executedFunctions.some(fn => fn?.result?.success !== false) && (
                    <div className="mt-2 flex flex-wrap gap-1">
                        {msg.executedFunctions
                            .filter((fn) => fn?.result?.success !== false)
                            .map((fn, i) => (
                                <span
                                    key={i}
                                    className="inline-flex items-center gap-1 text-[10px] bg-green-500/15 text-green-300
                                               px-2 py-0.5 rounded-full border border-green-400/25"
                                >
                                    <CheckCircle2 className="w-2.5 h-2.5" /> {fn.name}
                                </span>
                            ))}
                    </div>
                )}
            </motion.div>
        );
    };

    /* ════════════════ Compute bubble position ═════════════════ */

    const bubbleStyle = useMemo(() => {
        if (typeof window === "undefined") {
            return { position: "fixed" as const, display: "none" };
        }
        const isNearBottom = pos.y > window.innerHeight * 0.5;
        const isNearRight = pos.x > window.innerWidth * 0.5;
        return {
            position: "fixed" as const,
            // If mascot is near bottom, bubble appears above; otherwise below
            ...(isNearBottom
                ? { bottom: window.innerHeight - pos.y + 10 }
                : { top: pos.y + 68 }),
            // If mascot is near right edge, anchor to right; otherwise left
            ...(isNearRight
                ? { right: window.innerWidth - pos.x - 32 }
                : { left: pos.x - 10 }),
            zIndex: 59,
            display: "flex",
            flexDirection: "column" as const,
            alignItems: isNearRight ? "flex-end" : "flex-start",
        };
    }, [pos]);

    /* ════════════════════ RENDER ════════════════════════ */

    return (
        <>
            {/* ─── Draggable Cone Mascot ─── */}
            <div
                onPointerDown={handlePointerDown}
                onPointerMove={handlePointerMove}
                onPointerUp={handlePointerUp}
                onPointerCancel={handlePointerUp}
                onLostPointerCapture={handlePointerUp}
                onClick={handleClick}
                style={{
                    position: "fixed",
                    left: pos.x,
                    top: pos.y,
                    zIndex: 61,
                    touchAction: "none",
                    userSelect: "none",
                    cursor: dragging ? "grabbing" : "grab",
                    ...(isWidget ? { WebkitAppRegion: "drag", cursor: "move" } : {})
                } as React.CSSProperties}
                className={`p-1 rounded-full
                           bg-gradient-to-br from-violet-600/80 to-purple-800/80
                           shadow-[0_0_30px_rgba(139,92,246,0.5)] border border-violet-400/30
                           backdrop-blur-sm transition-transform hover:shadow-[0_0_40px_rgba(139,92,246,0.7)]
                           ${dragging ? "scale-110" : ""}`}
                title="Arrastra para mover • Toca para abrir"
            >
                <ConeMascot state={mascotState} size={52} />
            </div>

            {/* ─── Floating Response Bubbles (materialize in the air) ─── */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.85, y: 30 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.85, y: 30 }}
                        transition={{ type: "spring", damping: 18, stiffness: 200 }}
                        style={bubbleStyle}
                        className="gap-2"
                    >
                        {/* Only show recent messages floating in the air instead of a chat history box */}
                        {lastExchange.slice(-2).map(renderMessage)}

                        {/* Thinking indicator floating */}
                        {isLoading && (
                            <motion.div
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                className="flex items-center gap-2 px-4 py-2 rounded-2xl bg-black/50 backdrop-blur-xl text-cyan-300 text-xs border border-cyan-500/20 shadow-[0_8px_32px_rgba(0,0,0,0.5)] mb-2"
                            >
                                <Loader2 className="w-3.5 h-3.5 animate-spin" />
                                Materializando...
                            </motion.div>
                        )}

                        {/* Contextual Suggestions */}
                        {messages.length <= 2 && contextualSuggestions.length > 0 && (
                            <div className="flex flex-wrap gap-1.5 w-[320px] mb-1">
                                {contextualSuggestions.map(s => (
                                    <button key={s} onClick={() => sendMessage(s)}
                                        className="px-3 py-1 text-[11px] rounded-full bg-violet-500/20 text-violet-300 hover:bg-violet-500/40 border border-violet-400/20 transition-all">
                                        {s}
                                    </button>
                                ))}
                            </div>
                        )}

                        {/* Floating input pill + controls */}
                        <div className="flex gap-2 w-[320px] bg-black/60 backdrop-blur-2xl p-1.5 rounded-full border border-violet-400/30 shadow-[0_8px_32px_rgba(0,0,0,0.5)]">
                            <input
                                ref={inputRef}
                                type="text"
                                value={input}
                                onChange={(e) => setInput(e.target.value)}
                                onKeyDown={handleKeyDown}
                                placeholder="Escribe qué necesitas..."
                                disabled={isLoading}
                                className="flex-1 px-4 py-2 bg-transparent text-violet-100 rounded-full
                                           focus:outline-none placeholder:text-violet-300/60 text-sm font-medium"
                            />
                            <button
                                onClick={() => sendMessage()}
                                disabled={!input.trim() || isLoading}
                                className="bg-gradient-to-br from-violet-500 to-fuchsia-600 text-white p-2.5
                                           rounded-full hover:from-violet-400 hover:to-fuchsia-500
                                           disabled:opacity-30 disabled:cursor-not-allowed transition-all
                                           shadow-[0_0_12px_rgba(139,92,246,0.4)]"
                            >
                                {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                            </button>
                        </div>
                        {/* Mini controls: Wipe Memory */}
                        <div className="flex items-center gap-2 mt-1">
                            <button onClick={wipeMemory} title="Borrar memoria"
                                className="p-1.5 rounded-full bg-gray-500/20 text-gray-400 hover:bg-red-500/20 hover:text-red-400 transition-all hover:scale-110 text-xs">
                                🧹
                            </button>
                            <span className="text-[10px] text-violet-400/50 ml-auto">↑↓ historial</span>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </>
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { LayoutDashboard, Server, Users, Settings, Database, FileCode, Zap, Palette, Menu, X, DollarSign } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

const sidebarItems = [
    { icon: LayoutDashboard, label: "Panel Principal", href: "/" },
    { icon: Server, label: "Servidores VPS", href: "/vps" },
    { icon: Database, label: "Servicios", href: "/services" },
    { icon: Users, label: "Clientes", href: "/clients" },
    { icon: DollarSign, label: "Facturación", href: "/billing" },
    { icon: Palette, label: "Pizarra Blanca", href: "/whiteboard" },
    { icon: FileCode, label: "Editor Config", href: "/config-editor" },
    { icon: Settings, label: "Configuración", href: "/settings" },
];

export function AppSidebar() {
    const pathname = usePathname();
    const [isOpen, setIsOpen] = useState(false);
    const [vpsCount, setVpsCount] = useState<number | string>("...");

    useEffect(() => {
        fetch("/api/stats")
            .then(res => res.json())
            .then(data => {
                if (data.success) {
                    setVpsCount(data.data.vps);
                }
            })
            .catch(() => setVpsCount(0));
    }, []);

    if (pathname === "/login") return null;

    const toggleSidebar = () => setIsOpen(!isOpen);

    const SidebarContent = () => (
        <>
            <div className="p-5 border-b border-gray-100">
                <Link href="/" className="flex items-center gap-3 group" onClick={() => setIsOpen(false)}>
                    <div className="w-12 h-12 flex items-center justify-center group-hover:scale-105 transition-transform">
                        {/* eslint-disable-next-line @next/next/no-img-element */}
                        <img
                            src="/renace-logo-icon.svg"
                            alt="Renace Logo"
                            className="w-full h-full object-contain"
                        />
                    </div>
                    <div>
                        <h1 className="text-lg font-bold text-gray-900 tracking-tight">RENACE Tech</h1>
                        <p className="text-[10px] text-gray-500 font-medium uppercase tracking-widest">Digital Solutions</p>
                    </div>
                </Link>
            </div>

            {/* Navigation */}
            <nav className="flex-1 p-3 space-y-1 overflow-y-auto">
                <p className="px-3 py-2 text-xs font-semibold text-gray-400 uppercase tracking-wider">Menú</p>
                {sidebarItems.map((item) => {
                    const isActive = pathname === item.href;
                    return (
                        <Link
                            key={item.href}
                            href={item.href}
                            onClick={() => setIsOpen(false)}
                            className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 group relative ${isActive
                                ? "bg-violet-100 text-violet-700 font-medium"
                                : "text-gray-600 hover:bg-gray-100 hover:text-gray-900"
                                }`}
                        >
                            {isActive && (
                                <motion.div
                                    layoutId="activeTab"
                                    className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-violet-500 rounded-r-full"
                                    transition={{ type: "spring", stiffness: 300, damping: 30 }}
                                />
                            )}
                            <item.icon size={20} strokeWidth={isActive ? 2.5 : 2} />
                            <span className="text-sm">{item.label}</span>
                            {item.label === "Pizarra Blanca" && (
                                <span className="ml-auto text-[10px] bg-violet-500 text-white px-1.5 py-0.5 rounded-full font-medium">
                                    NUEVO
                                </span>
                            )}
                        </Link>
                    );
                })}
            </nav>

            {/* Quick Stats */}
            <div className="p-3 border-t border-gray-100">
                <div className="bg-gradient-to-br from-violet-50 to-purple-50 rounded-xl p-4">
                    <div className="flex items-center justify-between mb-2">
                        <span className="text-xs font-medium text-gray-500">VPS Activos</span>
                        <span className="text-lg font-bold text-violet-600">{vpsCount}</span>
                    </div>
                    <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden">
                        <div className="h-full bg-gradient-to-r from-violet-500 to-purple-500 rounded-full" style={{ width: vpsCount === "..." || vpsCount === 0 ? "0%" : "100%" }} />
                    </div>
                    <p className="text-[10px] text-gray-400 mt-1">{vpsCount === 0 ? "Sin servidores" : "Todos funcionales"}</p>
                </div>
            </div>

            {/* User */}
            <div className="p-3 border-t border-gray-100">
                <div className="flex items-center gap-3 px-3 py-2">
                    <div className="w-9 h-9 rounded-full bg-gradient-to-br from-violet-400 to-purple-500 flex items-center justify-center text-white font-bold text-sm shadow-md">
                        A
                    </div>
                    <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-gray-900 truncate">Admin</p>
                        <p className="text-xs text-gray-500 truncate">admin@renace.tech</p>
                    </div>
                </div>
            </div>
        </>
    );

    return (
        <>
            {/* Mobile Toggle */}
            <button
                onClick={toggleSidebar}
                className="lg:hidden fixed bottom-6 right-6 z-50 w-14 h-14 rounded-full bg-violet-600 text-white shadow-xl flex items-center justify-center hover:scale-110 active:scale-95 transition-transform"
            >
                {isOpen ? <X size={24} /> : <Menu size={24} />}
            </button>

            {/* Desktop Sidebar */}
            <aside className="hidden lg:flex w-64 h-screen bg-white border-r-2 border-gray-200 flex-col shadow-sm sticky top-0">
                <SidebarContent />
            </aside>

            {/* Mobile Sidebar Overlay */}
            <AnimatePresence>
                {isOpen && (
                    <motion.aside
                        initial={{ x: "-100%" }}
                        animate={{ x: 0 }}
                        exit={{ x: "-100%" }}
                        transition={{ type: "spring", damping: 25, stiffness: 200 }}
                        className="fixed inset-y-0 left-0 z-40 w-72 bg-white flex flex-col shadow-2xl lg:hidden"
                    >
                        <SidebarContent />
                    </motion.aside>
                )}
            </AnimatePresence>

            {/* Backdrop */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={() => setIsOpen(false)}
                        className="fixed inset-0 bg-black/20 backdrop-blur-sm z-30 lg:hidden"
                    />
                )}
            </AnimatePresence>
        </>
    );
}

"use client";

import { useState } from "react";
import { Download, Database, FolderArchive, Server, Loader2, CheckCircle, X, FileArchive } from "lucide-react";

interface BackupPanelProps {
    host: string;
    port: number;
    username: string;
    onPasswordRequest: () => Promise<string | null>;
}

interface BackupResult {
    success: boolean;
    type: string;
    filename: string;
    size?: string;
    path?: string;
    duration?: number;
    error?: string;
}

const BACKUP_TYPES = [
    { id: "postgres", label: "PostgreSQL", icon: Database, description: "Base de datos PostgreSQL" },
    { id: "mysql", label: "MySQL", icon: Database, description: "Base de datos MySQL" },
    { id: "odoo", label: "Odoo Instance", icon: Server, description: "Instancia Odoo completa" },
    { id: "docker", label: "Docker DB", icon: Database, description: "DB desde container Docker" },
    { id: "files", label: "Archivos", icon: FolderArchive, description: "Directorio específico" },
    { id: "full", label: "Backup Completo", icon: FileArchive, description: "/opt, nginx, home" },
];

export default function BackupPanel({ host, port, username, onPasswordRequest }: BackupPanelProps) {
    const [password, setPassword] = useState<string | null>(null);
    const [selectedType, setSelectedType] = useState<string>("postgres");
    const [target, setTarget] = useState("");
    const [isRunning, setIsRunning] = useState(false);
    const [result, setResult] = useState<BackupResult | null>(null);
    const [showPanel, setShowPanel] = useState(false);

    const runBackup = async () => {
        let pwd = password;
        if (!pwd) {
            pwd = await onPasswordRequest();
            if (!pwd) return;
            setPassword(pwd);
        }

        setIsRunning(true);
        setResult(null);

        try {
            const res = await fetch("/api/backup", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    host,
                    port,
                    username,
                    password: pwd,
                    type: selectedType,
                    target: target || undefined,
                }),
            });
            const data = await res.json();

            if (data.success) {
                setResult(data.data);
            } else {
                setResult({ success: false, type: selectedType, filename: "", error: data.error });
            }
        } catch (err) {
            setResult({ success: false, type: selectedType, filename: "", error: "Error de conexión" });
        } finally {
            setIsRunning(false);
        }
    };

    if (!showPanel) {
        return (
            <button
                onClick={() => setShowPanel(true)}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition"
            >
                <Download className="w-4 h-4" />
                Backup
            </button>
        );
    }

    return (
        <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 bg-gray-900 border-b border-gray-700">
                <div className="flex items-center gap-3">
                    <Download className="w-5 h-5 text-blue-400" />
                    <span className="text-white font-medium">Panel de Backups</span>
                </div>
                <button onClick={() => setShowPanel(false)} className="text-gray-400 hover:text-white">
                    <X className="w-4 h-4" />
                </button>
            </div>

            <div className="p-4 space-y-4">
                {/* Backup Type Selection */}
                <div>
                    <label className="text-sm text-gray-400 mb-2 block">Tipo de Backup</label>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                        {BACKUP_TYPES.map((type) => (
                            <button
                                key={type.id}
                                onClick={() => setSelectedType(type.id)}
                                className={`p-3 rounded-lg border transition text-left ${selectedType === type.id
                                        ? "border-blue-500 bg-blue-900/30"
                                        : "border-gray-600 hover:border-gray-500"
                                    }`}
                            >
                                <type.icon className={`w-4 h-4 mb-1 ${selectedType === type.id ? "text-blue-400" : "text-gray-400"}`} />
                                <div className="text-xs font-medium text-white">{type.label}</div>
                                <div className="text-[10px] text-gray-500">{type.description}</div>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Target Input */}
                {["postgres", "mysql", "odoo", "docker", "files"].includes(selectedType) && (
                    <div>
                        <label className="text-sm text-gray-400 mb-1 block">
                            {selectedType === "files" ? "Ruta a respaldar" :
                                selectedType === "docker" ? "Nombre del container" :
                                    selectedType === "odoo" ? "Nombre de instancia" : "Nombre de base de datos"}
                        </label>
                        <input
                            type="text"
                            value={target}
                            onChange={(e) => setTarget(e.target.value)}
                            placeholder={
                                selectedType === "files" ? "/opt/myapp" :
                                    selectedType === "docker" ? "odoo-container" :
                                        selectedType === "odoo" ? "odoo17" : "mi_base_datos"
                            }
                            className="w-full px-3 py-2 bg-gray-700 border border-gray-600 rounded-lg text-white text-sm focus:border-blue-500 focus:outline-none"
                        />
                    </div>
                )}

                {/* Execute Button */}
                <button
                    onClick={runBackup}
                    disabled={isRunning}
                    className="w-full py-3 bg-blue-600 hover:bg-blue-700 disabled:bg-gray-600 text-white font-medium rounded-lg transition flex items-center justify-center gap-2"
                >
                    {isRunning ? (
                        <>
                            <Loader2 className="w-4 h-4 animate-spin" />
                            Ejecutando backup...
                        </>
                    ) : (
                        <>
                            <Download className="w-4 h-4" />
                            Ejecutar Backup
                        </>
                    )}
                </button>

                {/* Result */}
                {result && (
                    <div className={`p-4 rounded-lg ${result.success ? "bg-green-900/30 border border-green-700" : "bg-red-900/30 border border-red-700"}`}>
                        <div className="flex items-start gap-3">
                            {result.success ? (
                                <CheckCircle className="w-5 h-5 text-green-400 mt-0.5" />
                            ) : (
                                <X className="w-5 h-5 text-red-400 mt-0.5" />
                            )}
                            <div className="flex-1">
                                <p className={`font-medium ${result.success ? "text-green-300" : "text-red-300"}`}>
                                    {result.success ? "Backup completado" : "Error en backup"}
                                </p>
                                {result.success ? (
                                    <div className="text-sm text-gray-300 mt-1 space-y-1">
                                        <p><span className="text-gray-500">Archivo:</span> {result.filename}</p>
                                        <p><span className="text-gray-500">Tamaño:</span> {result.size}</p>
                                        <p><span className="text-gray-500">Ruta:</span> {result.path}</p>
                                        <p><span className="text-gray-500">Duración:</span> {(result.duration! / 1000).toFixed(1)}s</p>
                                    </div>
                                ) : (
                                    <p className="text-sm text-red-400 mt-1">{result.error}</p>
                                )}
                            </div>
                        </div>
                    </div>
                )}

                {/* Info */}
                <p className="text-xs text-gray-500">
                    Los backups se guardan en <code className="bg-gray-700 px-1 rounded">/tmp/</code> del servidor.
                    Recuerda descargarlos o moverlos a una ubicación segura.
                </p>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { Terminal, Loader2, Play, X, Info } from "lucide-react";

interface SSHConsoleProps {
    host: string;
    port: number;
    username: string;
    onClose?: () => void;
}

interface CommandResult {
    command: string;
    output: string;
    success: boolean;
    timestamp: Date;
}

export default function SSHConsole({ host, port, username, onClose }: SSHConsoleProps) {
    const [password, setPassword] = useState("");
    const [isConnected, setIsConnected] = useState(false);
    const [isConnecting, setIsConnecting] = useState(false);
    const [command, setCommand] = useState("");
    const [isExecuting, setIsExecuting] = useState(false);
    const [history, setHistory] = useState<CommandResult[]>([]);
    const [serverInfo, setServerInfo] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);

    const connect = async () => {
        if (!password) return;
        setIsConnecting(true);
        setError(null);

        try {
            const res = await fetch("/api/ssh", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    host,
                    port,
                    username,
                    password,
                    action: "test",
                }),
            });
            const data = await res.json();

            if (data.success) {
                setIsConnected(true);
                // Get server info
                const infoRes = await fetch("/api/ssh", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        host,
                        port,
                        username,
                        password,
                        action: "info",
                    }),
                });
                const infoData = await infoRes.json();
                if (infoData.success) {
                    setServerInfo(infoData.data);
                }
            } else {
                setError(data.message || "Conexión fallida");
            }
        } catch (err) {
            setError("Error de conexión");
        } finally {
            setIsConnecting(false);
        }
    };

    const executeCommand = async () => {
        if (!command.trim() || !isConnected) return;
        setIsExecuting(true);

        try {
            const res = await fetch("/api/ssh", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    host,
                    port,
                    username,
                    password,
                    command: command.trim(),
                }),
            });
            const data = await res.json();

            setHistory((prev) => [
                ...prev,
                {
                    command: command.trim(),
                    output: data.output || data.error || "No output",
                    success: data.success,
                    timestamp: new Date(),
                },
            ]);
            setCommand("");
        } catch (err) {
            setHistory((prev) => [
                ...prev,
                {
                    command: command.trim(),
                    output: "Error ejecutando comando",
                    success: false,
                    timestamp: new Date(),
                },
            ]);
        } finally {
            setIsExecuting(false);
        }
    };

    const quickCommands = [
        { label: "Uptime", cmd: "uptime" },
        { label: "Disk", cmd: "df -h /" },
        { label: "Memory", cmd: "free -h" },
        { label: "Docker PS", cmd: "docker ps --format 'table {{.Names}}\t{{.Status}}'" },
        { label: "Services", cmd: "systemctl list-units --type=service --state=running | head -20" },
    ];

    if (!isConnected) {
        return (
            <div className="bg-gray-900 rounded-xl p-6 border border-gray-700">
                <div className="flex items-center gap-3 mb-4">
                    <Terminal className="w-6 h-6 text-green-400" />
                    <h3 className="text-lg font-bold text-white">SSH Console</h3>
                </div>
                <p className="text-gray-400 mb-4 text-sm">
                    Conectar a <span className="font-mono text-cyan-400">{username}@{host}:{port}</span>
                </p>
                {error && (
                    <div className="bg-red-900/50 text-red-300 px-4 py-2 rounded-lg mb-4 text-sm">
                        {error}
                    </div>
                )}
                <div className="flex gap-2">
                    <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        placeholder="Contraseña SSH"
                        className="flex-1 px-4 py-2 bg-gray-800 border border-gray-600 rounded-lg text-white focus:border-green-500 focus:outline-none"
                        onKeyDown={(e) => e.key === "Enter" && connect()}
                        autoFocus
                    />
                    <button
                        onClick={connect}
                        disabled={!password || isConnecting}
                        className="px-6 py-2 bg-green-600 hover:bg-green-700 disabled:bg-gray-600 rounded-lg text-white font-medium transition-colors flex items-center gap-2"
                    >
                        {isConnecting ? (
                            <Loader2 className="w-4 h-4 animate-spin" />
                        ) : (
                            <Play className="w-4 h-4" />
                        )}
                        Conectar
                    </button>
                    {onClose && (
                        <button
                            onClick={onClose}
                            className="px-3 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-white"
                        >
                            <X className="w-4 h-4" />
                        </button>
                    )}
                </div>
            </div>
        );
    }

    return (
        <div className="bg-gray-900 rounded-xl border border-gray-700 overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-2 bg-gray-800 border-b border-gray-700">
                <div className="flex items-center gap-3">
                    <div className="w-3 h-3 rounded-full bg-green-500" />
                    <span className="text-sm text-gray-300 font-mono">
                        {username}@{host}
                    </span>
                    {serverInfo && (
                        <span className="text-xs text-gray-500">
                            {serverInfo.os} • {serverInfo.uptime}
                        </span>
                    )}
                </div>
                {onClose && (
                    <button onClick={onClose} className="text-gray-400 hover:text-white">
                        <X className="w-4 h-4" />
                    </button>
                )}
            </div>

            {/* Server Info */}
            {serverInfo && (
                <div className="grid grid-cols-4 gap-2 p-3 bg-gray-800/50 border-b border-gray-700 text-xs">
                    <div>
                        <span className="text-gray-500">CPU:</span>
                        <span className="text-gray-300 ml-1">{serverInfo.cpu.substring(0, 25)}...</span>
                    </div>
                    <div>
                        <span className="text-gray-500">RAM:</span>
                        <span className="text-green-400 ml-1">{serverInfo.memory.used}/{serverInfo.memory.total}</span>
                    </div>
                    <div>
                        <span className="text-gray-500">Disk:</span>
                        <span className="text-yellow-400 ml-1">{serverInfo.disk.percent}</span>
                    </div>
                    <div>
                        <span className="text-gray-500">Hostname:</span>
                        <span className="text-cyan-400 ml-1">{serverInfo.hostname}</span>
                    </div>
                </div>
            )}

            {/* Quick Commands */}
            <div className="flex gap-2 p-2 bg-gray-800/30 border-b border-gray-700 overflow-x-auto">
                {quickCommands.map((qc) => (
                    <button
                        key={qc.cmd}
                        onClick={() => {
                            setCommand(qc.cmd);
                        }}
                        className="px-3 py-1 bg-gray-700 hover:bg-gray-600 rounded text-xs text-gray-300 whitespace-nowrap"
                    >
                        {qc.label}
                    </button>
                ))}
            </div>

            {/* Output */}
            <div className="h-64 overflow-y-auto p-4 font-mono text-sm" style={{ backgroundColor: "#1e1e2e" }}>
                {history.length === 0 ? (
                    <p className="text-gray-500">Ready. Escribe un comando...</p>
                ) : (
                    history.map((item, idx) => (
                        <div key={idx} className="mb-4">
                            <div className="flex items-center gap-2 text-green-400">
                                <span>$</span>
                                <span>{item.command}</span>
                            </div>
                            <pre className={`mt-1 whitespace-pre-wrap ${item.success ? "text-gray-300" : "text-red-400"}`}>
                                {item.output}
                            </pre>
                        </div>
                    ))
                )}
            </div>

            {/* Input */}
            <div className="flex items-center gap-2 p-3 bg-gray-800 border-t border-gray-700">
                <span className="text-green-400 font-mono">$</span>
                <input
                    type="text"
                    value={command}
                    onChange={(e) => setCommand(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && executeCommand()}
                    placeholder="Escribe un comando..."
                    className="flex-1 bg-transparent text-white focus:outline-none font-mono"
                    disabled={isExecuting}
                />
                <button
                    onClick={executeCommand}
                    disabled={isExecuting || !command.trim()}
                    className="px-4 py-1 bg-green-600 hover:bg-green-700 disabled:bg-gray-600 rounded text-white text-sm flex items-center gap-2"
                >
                    {isExecuting ? (
                        <Loader2 className="w-4 h-4 animate-spin" />
                    ) : (
                        <Play className="w-4 h-4" />
                    )}
                    Ejecutar
                </button>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { Terminal } from "xterm";
import { FitAddon } from "@xterm/addon-fit";
import "xterm/css/xterm.css";

interface SSHTerminalProps {
    host: string;
    port: number;
    username: string;
    onClose?: () => void;
}

export default function SSHTerminal({ host, port, username, onClose }: SSHTerminalProps) {
    const terminalRef = useRef<HTMLDivElement>(null);
    const termRef = useRef<Terminal | null>(null);
    const wsRef = useRef<WebSocket | null>(null);
    const [isConnecting, setIsConnecting] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [password, setPassword] = useState("");
    const [showPasswordPrompt, setShowPasswordPrompt] = useState(true);

    const connect = () => {
        if (!password) return;
        setShowPasswordPrompt(false);
        setIsConnecting(true);
        setError(null);

        // Initialize terminal
        const term = new Terminal({
            cursorBlink: true,
            fontSize: 14,
            fontFamily: '"Fira Code", "Cascadia Code", Consolas, monospace',
            theme: {
                background: "#1e1e2e",
                foreground: "#cdd6f4",
                cursor: "#f5e0dc",
                selectionBackground: "#45475a",
                black: "#45475a",
                red: "#f38ba8",
                green: "#a6e3a1",
                yellow: "#f9e2af",
                blue: "#89b4fa",
                magenta: "#f5c2e7",
                cyan: "#94e2d5",
                white: "#bac2de",
            },
        });

        const fitAddon = new FitAddon();
        term.loadAddon(fitAddon);

        if (terminalRef.current) {
            term.open(terminalRef.current);
            fitAddon.fit();
        }

        termRef.current = term;
        term.writeln("\x1b[1;34m[RNV Manager]\x1b[0m Conectando a " + host + "...");

        // Connect via WebSocket to our API
        const wsProtocol = window.location.protocol === "https:" ? "wss:" : "ws:";
        const wsUrl = `${wsProtocol}//${window.location.host}/api/ssh?host=${encodeURIComponent(host)}&port=${port}&username=${encodeURIComponent(username)}&password=${encodeURIComponent(password)}`;

        try {
            const ws = new WebSocket(wsUrl);
            wsRef.current = ws;

            ws.onopen = () => {
                setIsConnecting(false);
                term.writeln("\x1b[1;32m[RNV Manager]\x1b[0m Conexión establecida!");
                term.writeln("");
            };

            ws.onmessage = (event) => {
                term.write(event.data);
            };

            ws.onerror = () => {
                setError("Error de conexión WebSocket");
                setIsConnecting(false);
            };

            ws.onclose = () => {
                term.writeln("\n\x1b[1;31m[RNV Manager]\x1b[0m Conexión cerrada.");
                setIsConnecting(false);
            };

            // Send user input to server
            term.onData((data) => {
                if (ws.readyState === WebSocket.OPEN) {
                    ws.send(data);
                }
            });

            // Handle resize
            const handleResize = () => {
                fitAddon.fit();
                if (ws.readyState === WebSocket.OPEN) {
                    ws.send(JSON.stringify({
                        type: "resize",
                        cols: term.cols,
                        rows: term.rows
                    }));
                }
            };

            window.addEventListener("resize", handleResize);

            return () => {
                window.removeEventListener("resize", handleResize);
            };
        } catch (err) {
            setError("No se pudo conectar al servidor SSH");
            setIsConnecting(false);
        }
    };

    useEffect(() => {
        return () => {
            if (wsRef.current) {
                wsRef.current.close();
            }
            if (termRef.current) {
                termRef.current.dispose();
            }
        };
    }, []);

    if (showPasswordPrompt) {
        return (
            <div className="bg-gray-900 rounded-xl p-6 text-white">
                <h3 className="text-lg font-bold mb-4 text-green-400">
                    🔐 Conexión SSH a {host}
                </h3>
                <p className="text-gray-400 mb-4">
                    Usuario: <span className="text-white font-mono">{username}</span>
                </p>
                <div className="flex gap-2">
                    <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        placeholder="Contraseña SSH"
                        className="flex-1 px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg focus:border-green-500 focus:outline-none"
                        onKeyDown={(e) => e.key === "Enter" && connect()}
                        autoFocus
                    />
                    <button
                        onClick={connect}
                        disabled={!password}
                        className="px-6 py-2 bg-green-600 hover:bg-green-700 disabled:bg-gray-600 rounded-lg font-medium transition-colors"
                    >
                        Conectar
                    </button>
                    {onClose && (
                        <button
                            onClick={onClose}
                            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg"
                        >
                            Cancelar
                        </button>
                    )}
                </div>
            </div>
        );
    }

    return (
        <div className="bg-gray-900 rounded-xl overflow-hidden">
            <div className="flex items-center justify-between px-4 py-2 bg-gray-800 border-b border-gray-700">
                <div className="flex items-center gap-2">
