"use client";

import * as React from "react";
import { createContext, useContext, useState, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, CheckCircle, AlertCircle, Info, AlertTriangle } from "lucide-react";

type ToastType = "success" | "error" | "info" | "warning";

interface Toast {
    id: string;
    message: string;
    type: ToastType;
    duration?: number;
}

interface ToastContextType {
    toasts: Toast[];
    addToast: (message: string, type?: ToastType, duration?: number) => void;
    removeToast: (id: string) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export function useToast() {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error("useToast must be used within a ToastProvider");
    }
    return context;
}

export function ToastProvider({ children }: { children: React.ReactNode }) {
    const [toasts, setToasts] = useState<Toast[]>([]);

    const addToast = useCallback((message: string, type: ToastType = "info", duration: number = 4000) => {
        const id = Math.random().toString(36).substring(7);
        setToasts((prev) => [...prev, { id, message, type, duration }]);

        if (duration > 0) {
            setTimeout(() => {
                removeToast(id);
            }, duration);
        }
    }, []);

    const removeToast = useCallback((id: string) => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
    }, []);

    return (
        <ToastContext.Provider value={{ toasts, addToast, removeToast }}>
            {children}
            <ToastContainer toasts={toasts} removeToast={removeToast} />
        </ToastContext.Provider>
    );
}

function ToastContainer({ toasts, removeToast }: { toasts: Toast[]; removeToast: (id: string) => void }) {
    const icons = {
        success: CheckCircle,
        error: AlertCircle,
        info: Info,
        warning: AlertTriangle,
    };

    const colors = {
        success: "bg-green-50 border-green-200 text-green-800",
        error: "bg-red-50 border-red-200 text-red-800",
        info: "bg-blue-50 border-blue-200 text-blue-800",
        warning: "bg-yellow-50 border-yellow-200 text-yellow-800",
    };

    const iconColors = {
        success: "text-green-500",
        error: "text-red-500",
        info: "text-blue-500",
        warning: "text-yellow-500",
    };

    return (
        <div className="fixed bottom-6 right-6 z-50 flex flex-col gap-3 max-w-sm">
            <AnimatePresence>
                {toasts.map((toast) => {
                    const Icon = icons[toast.type];
                    return (
                        <motion.div
                            key={toast.id}
                            initial={{ opacity: 0, y: 20, scale: 0.95 }}
                            animate={{ opacity: 1, y: 0, scale: 1 }}
                            exit={{ opacity: 0, x: 100, scale: 0.95 }}
                            className={`flex items-start gap-3 p-4 rounded-xl border-2 shadow-lg ${colors[toast.type]}`}
                        >
                            <Icon className={`w-5 h-5 mt-0.5 flex-shrink-0 ${iconColors[toast.type]}`} />
                            <p className="text-sm font-medium flex-1">{toast.message}</p>
                            <button
                                onClick={() => removeToast(toast.id)}
                                className="text-gray-400 hover:text-gray-600 transition-colors"
                            >
                                <X size={16} />
                            </button>
                        </motion.div>
                    );
                })}
            </AnimatePresence>
        </div>
    );
}

import { apiCache, CACHE_KEYS } from "./cache";

const HOSTINGER_API_BASE = "https://developers.hostinger.com";
const API_TIMEOUT = 10000; // 10 seconds timeout

export interface HostingerVPS {
    id: number;
    hostname: string;
    state: string;
    cpus: number;
    memory: number;
    disk: number;
    bandwidth: number;
    ns1?: string;
    ns2?: string;
    created_at: string;
    ipv4?: { id: number; address: string }[];
    ipv6?: { id: number; address: string }[];
    template?: { id: number; name: string; description: string };
    data_center?: { id: number; name: string; location: string };
    plan?: { id: number; name: string };
}

interface HostingerVPSResponse {
    data: HostingerVPS[];
    meta?: {
        current_page: number;
        last_page: number;
        per_page: number;
        total: number;
    };
}

// Fetch with timeout
async function fetchWithTimeout(url: string, options: RequestInit, timeout: number): Promise<Response> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    try {
        const response = await fetch(url, {
            ...options,
            signal: controller.signal,
        });
        clearTimeout(timeoutId);
        return response;
    } catch (error: any) {
        clearTimeout(timeoutId);
        if (error.name === "AbortError") {
            throw new Error("Request timeout - Hostinger API took too long to respond");
        }
        throw error;
    }
}

// Retry with exponential backoff
async function fetchWithRetry<T>(
    fetchFn: () => Promise<T>,
    retries: number = 3,
    delay: number = 1000
): Promise<T> {
    for (let i = 0; i < retries; i++) {
        try {
            return await fetchFn();
        } catch (error) {
            if (i === retries - 1) throw error;
            await new Promise((resolve) => setTimeout(resolve, delay * Math.pow(2, i)));
        }
    }
    throw new Error("Max retries reached");
}

export async function getHostingerVPSList(forceRefresh: boolean = false): Promise<HostingerVPS[]> {
    // Check cache first (unless force refresh)
    if (!forceRefresh) {
        const cached = apiCache.get<HostingerVPS[]>(CACHE_KEYS.HOSTINGER_VPS);
        if (cached) {
            console.log("✅ Returning cached VPS data");
            return cached;
        }
    }

    const token = process.env.HOSTINGER_API_TOKEN;

    if (!token) {
        throw new Error("HOSTINGER_API_TOKEN not configured. Go to Settings to add your API key.");
    }

    console.log("🔄 Fetching VPS from Hostinger API...");

    const fetchVPS = async (): Promise<HostingerVPS[]> => {
        const allVPS: HostingerVPS[] = [];
        let currentPage = 1;
        let hasMorePages = true;

        while (hasMorePages) {
            const url = `${HOSTINGER_API_BASE}/api/vps/v1/virtual-machines?page=${currentPage}`;

            const response = await fetchWithTimeout(
                url,
                {
                    headers: {
                        "Authorization": `Bearer ${token}`,
                        "Content-Type": "application/json",
                    },
                    cache: "no-store",
                },
                API_TIMEOUT
            );

            if (!response.ok) {
                const errorText = await response.text();
                console.error("❌ Hostinger API Error:", response.status, errorText);
                throw new Error(`Hostinger API error: ${response.status} - ${response.statusText}`);
            }

            const data = await response.json();

            // Handle both array response and {data: [...]} response
            const vpsList: HostingerVPS[] = Array.isArray(data) ? data : (data.data || []);

            if (vpsList.length > 0) {
                allVPS.push(...vpsList);
            }

            // Check pagination from meta if available
            if (data.meta && currentPage < data.meta.last_page) {
                currentPage++;
            } else {
                hasMorePages = false;
            }
        }

        return allVPS;
    };

    try {
        const vpsList = await fetchWithRetry(fetchVPS, 2, 2000);

        // Cache the result for 5 minutes
        apiCache.set(CACHE_KEYS.HOSTINGER_VPS, vpsList, 5 * 60 * 1000);
        console.log(`✅ Cached ${vpsList.length} VPS servers`);

        return vpsList;
    } catch (error: any) {
        console.error("❌ Failed to fetch VPS:", error.message);
        throw error;
    }
}

export function invalidateVPSCache(): void {
    apiCache.invalidate(CACHE_KEYS.HOSTINGER_VPS);
    console.log("🗑️ VPS cache invalidated");
}

export async function getHostingerVPSDetails(vpsId: string): Promise<HostingerVPS | null> {
    const token = process.env.HOSTINGER_API_TOKEN;

    if (!token) {
        throw new Error("HOSTINGER_API_TOKEN not configured");
    }

    try {
        const response = await fetchWithTimeout(
            `${HOSTINGER_API_BASE}/api/vps/v1/virtual-machines/${vpsId}`,
            {
                headers: {
                    "Authorization": `Bearer ${token}`,
                    "Content-Type": "application/json",
                },
            },
            API_TIMEOUT
        );

        if (!response.ok) {
            console.error("Hostinger API Error:", response.status);
            return null;
        }

        const data = await response.json();
        return data.data || data;
    } catch (error) {
        console.error("Failed to fetch VPS details:", error);
        return null;
    }
}

export async function restartHostingerVPS(vpsId: string): Promise<{ success: boolean; message: string }> {
    const token = process.env.HOSTINGER_API_TOKEN;

    if (!token) {
        return { success: false, message: "API token not configured" };
    }

    try {
        const response = await fetchWithTimeout(
            `${HOSTINGER_API_BASE}/api/vps/v1/virtual-machines/${vpsId}/restart`,
            {
                method: "POST",
                headers: {
                    "Authorization": `Bearer ${token}`,
                    "Content-Type": "application/json",
                },
            },
            API_TIMEOUT
        );

        if (response.ok) {
            // Invalidate cache after restart
            invalidateVPSCache();
            return { success: true, message: "VPS restart initiated" };
        } else {
            return { success: false, message: `Error: ${response.status}` };
        }
    } catch (error: any) {
        return { success: false, message: error.message };
    }
}

/**
 * Odoo XML-RPC Client
 * Connects to Odoo using XML-RPC protocol
 * 
 * Configuration via environment variables:
 * - ODOO_URL: Base URL of Odoo server (e.g., https://renace.tech)
 * - ODOO_DB: Database name
 * - ODOO_USERNAME: User email/login
 * - ODOO_API_KEY: API Key for authentication
 */

import { OdooConfig, OdooPartner, OdooInvoice, OdooProduct, OdooResponse } from "./types";

// Simple XML-RPC client implementation for Odoo
class OdooClient {
    private config: OdooConfig;
    private uid: number | null = null;

    constructor(config?: Partial<OdooConfig>) {
        this.config = {
            url: config?.url || process.env.ODOO_URL || "",
            db: config?.db || process.env.ODOO_DB || "",
            username: config?.username || process.env.ODOO_USERNAME || "",
            apiKey: config?.apiKey || process.env.ODOO_API_KEY || "",
        };
    }

    private buildXmlRpcRequest(method: string, params: any[]): string {
        const escapeXml = (str: string) => str
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;");

        const valueToXml = (val: any): string => {
            if (val === null || val === undefined) return "<value><boolean>0</boolean></value>";
            if (typeof val === "boolean") return `<value><boolean>${val ? 1 : 0}</boolean></value>`;
            if (typeof val === "number") {
                return Number.isInteger(val)
                    ? `<value><int>${val}</int></value>`
                    : `<value><double>${val}</double></value>`;
            }
            if (typeof val === "string") return `<value><string>${escapeXml(val)}</string></value>`;
            if (Array.isArray(val)) {
                return `<value><array><data>${val.map(valueToXml).join("")}</data></array></value>`;
            }
            if (typeof val === "object") {
                const members = Object.entries(val)
                    .map(([k, v]) => `<member><name>${k}</name>${valueToXml(v)}</member>`)
                    .join("");
                return `<value><struct>${members}</struct></value>`;
            }
            return `<value><string>${String(val)}</string></value>`;
        };

        const paramsXml = params.map(p => `<param>${valueToXml(p)}</param>`).join("");
        return `<?xml version="1.0"?><methodCall><methodName>${method}</methodName><params>${paramsXml}</params></methodCall>`;
    }

    private parseXmlRpcResponse(xml: string): any {
        // Simple XML parser for Odoo responses
        const getTagContent = (str: string, tag: string): string | null => {
            const regex = new RegExp(`<${tag}>([\\s\\S]*?)</${tag}>`);
            const match = str.match(regex);
            return match ? match[1] : null;
        };

        const parseValue = (valueStr: string): any => {
            if (valueStr.includes("<int>")) return parseInt(getTagContent(valueStr, "int") || "0");
            if (valueStr.includes("<i4>")) return parseInt(getTagContent(valueStr, "i4") || "0");
            if (valueStr.includes("<double>")) return parseFloat(getTagContent(valueStr, "double") || "0");
            if (valueStr.includes("<boolean>")) return getTagContent(valueStr, "boolean") === "1";
            if (valueStr.includes("<string>")) return getTagContent(valueStr, "string") || "";
            if (valueStr.includes("<array>")) {
                const data = getTagContent(valueStr, "data") || "";
                const values = data.match(/<value>[\s\S]*?<\/value>/g) || [];
                return values.map(parseValue);
            }
            if (valueStr.includes("<struct>")) {
                const result: any = {};
                const members = valueStr.match(/<member>[\s\S]*?<\/member>/g) || [];
                for (const member of members) {
                    const name = getTagContent(member, "name");
                    const val = member.match(/<value>[\s\S]*<\/value>/);
                    if (name && val) result[name] = parseValue(val[0]);
                }
                return result;
            }
            // Default: return as string
            const content = getTagContent(valueStr, "value");
            return content?.trim() || valueStr;
        };

        // Check for fault
        if (xml.includes("<fault>")) {
            const faultValue = getTagContent(xml, "fault") || "";
            const fault = parseValue(faultValue);
            throw new Error(fault.faultString || "XML-RPC Fault");
        }

        const params = getTagContent(xml, "params");
        if (!params) return null;

        const value = params.match(/<value>[\s\S]*<\/value>/);
        return value ? parseValue(value[0]) : null;
    }

    private async xmlRpcCall(endpoint: string, method: string, params: any[]): Promise<any> {
        const url = `${this.config.url}${endpoint}`;
        const body = this.buildXmlRpcRequest(method, params);

        console.log(`[Odoo] Calling ${method} at ${url}`);

        const response = await fetch(url, {
            method: "POST",
            headers: {
                "Content-Type": "text/xml",
            },
            body,
        });

        if (!response.ok) {
            throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }

        const text = await response.text();
        return this.parseXmlRpcResponse(text);
    }

    /**
     * Authenticate with Odoo and get uid
     */
    async authenticate(): Promise<number> {
        if (this.uid) return this.uid;

        const result = await this.xmlRpcCall(
            "/xmlrpc/2/common",
            "authenticate",
            [this.config.db, this.config.username, this.config.apiKey, {}]
        );

        if (!result || result === false) {
            throw new Error("Authentication failed");
        }

        this.uid = result as number;
        console.log(`[Odoo] Authenticated as UID: ${this.uid}`);
        return this.uid as number;
    }

    /**
     * Execute a method on Odoo model
     */
    async execute(model: string, method: string, args: any[], kwargs: any = {}): Promise<any> {
        const uid = await this.authenticate();
        return this.xmlRpcCall(
            "/xmlrpc/2/object",
            "execute_kw",
            [this.config.db, uid, this.config.apiKey, model, method, args, kwargs]
        );
    }

    /**
     * Search and read records
     */
    async searchRead(model: string, domain: any[] = [], fields: string[] = [], limit?: number): Promise<any[]> {
        const kwargs: any = { fields };
        if (limit) kwargs.limit = limit;
        return this.execute(model, "search_read", [domain], kwargs);
    }

    /**
     * Create a new record
     */
    async create(model: string, values: any): Promise<number> {
        return this.execute(model, "create", [values]);
    }

    /**
     * Update existing records
     */
    async write(model: string, ids: number[], values: any): Promise<boolean> {
        return this.execute(model, "write", [ids, values]);
    }

    // ============ Business Methods ============

    /**
     * Get partners (customers/suppliers)
     */
    async getPartners(limit = 100): Promise<OdooPartner[]> {
        return this.searchRead(
            "res.partner",
            [],
            ["id", "name", "email", "phone", "company_type", "street", "city", "vat"],
            limit
        );
    }

    /**
     * Create or update partner from RNV client
     */
    async syncPartner(data: OdooPartner): Promise<number> {
        // Try to find existing partner by email
        if (data.email) {
            const existing = await this.searchRead("res.partner", [["email", "=", data.email]], ["id"], 1);
            if (existing.length > 0) {
                await this.write("res.partner", [existing[0].id], data);
                return existing[0].id;
            }
        }
        return this.create("res.partner", data);
    }

    /**
     * Get products
     */
    async getProducts(limit = 100): Promise<OdooProduct[]> {
        return this.searchRead(
            "product.product",
            [],
            ["id", "name", "list_price", "default_code", "type"],
            limit
        );
    }

    /**
     * Create invoice
     */
    async createInvoice(partnerId: number, lines: Array<{ name: string; quantity: number; price_unit: number }>): Promise<number> {
        const invoiceLines = lines.map(line => [0, 0, {
            name: line.name,
            quantity: line.quantity,
            price_unit: line.price_unit,
        }]);

        const invoiceId = await this.create("account.move", {
            partner_id: partnerId,
            move_type: "out_invoice",
            invoice_line_ids: invoiceLines,
        });

        console.log(`[Odoo] Created invoice ${invoiceId} for partner ${partnerId}`);
        return invoiceId;
    }

    /**
     * Get invoices
     */
    async getInvoices(limit = 50): Promise<any[]> {
        return this.searchRead(
            "account.move",
            [["move_type", "=", "out_invoice"]],
            ["id", "name", "partner_id", "invoice_date", "amount_total", "state"],
            limit
        );
    }

    /**
     * Test connection
     */
    async testConnection(): Promise<OdooResponse<{ uid: number; version: any }>> {
        try {
            const version = await this.xmlRpcCall("/xmlrpc/2/common", "version", []);
            const uid = await this.authenticate();
            return { success: true, data: { uid, version } };
        } catch (error: any) {
            return { success: false, error: error.message };
        }
    }
}

// Singleton instance
let odooClient: OdooClient | null = null;

export function getOdooClient(config?: Partial<OdooConfig>): OdooClient {
    if (!odooClient || config) {
        odooClient = new OdooClient(config);
    }
    return odooClient;
}

export { OdooClient };
export default getOdooClient;

/**
 * Odoo Sync Module
 * Provides silent synchronization of clients/partners between Odoo and local database
 */

import { OdooClient } from "./client";
import prisma from "@/lib/prisma";
import type { Client, VPS, Service, Payment } from "@prisma/client";

// Type for Odoo Partner response
interface OdooPartnerData {
    id: number;
    name: string;
    email?: string | false;
    phone?: string | false;
    vat?: string | false;
    street?: string | false;
    city?: string | false;
    country_id?: [number, string] | false;
    company_type?: string;
}

export interface SyncResult {
    success: boolean;
    synced: number;
    created: number;
    updated: number;
    errors: string[];
}

/**
 * Sync partners from Odoo to local database
 * Creates new clients or updates existing ones based on odooPartnerId
 */
export async function syncOdooPartners(): Promise<SyncResult> {
    const result: SyncResult = {
        success: false,
        synced: 0,
        created: 0,
        updated: 0,
        errors: [],
    };

    try {
        const odoo = new OdooClient();
        await odoo.authenticate();

        // Fetch partners from Odoo (customers only)
        const partners: OdooPartnerData[] = await odoo.searchRead(
            "res.partner",
            [["customer_rank", ">", 0]],
            ["id", "name", "email", "phone", "vat", "street", "city", "country_id", "company_type"],
            100
        );

        console.log(`[Odoo Sync] Found ${partners?.length || 0} partners in Odoo`);

        // Guard against null/undefined response
        if (!partners || !Array.isArray(partners) || partners.length === 0) {
            result.success = true;
            console.log("[Odoo Sync] No partners to sync");
            return result;
        }

        for (const partner of partners) {
            try {
                // Check if client exists by odooPartnerId
                const existingClient = await prisma.client.findFirst({
                    where: { odooPartnerId: partner.id },
                });

                const odooData = {
                    vat: partner.vat || null,
                    street: partner.street || null,
                    city: partner.city || null,
                    country: partner.country_id ? partner.country_id[1] : null,
                    companyType: partner.company_type || "person",
                };

                if (existingClient) {
                    // Update existing client
                    await prisma.client.update({
                        where: { id: existingClient.id },
                        data: {
                            name: partner.name,
                            email: partner.email || existingClient.email,
                            phone: partner.phone || existingClient.phone,
                            odooData: odooData,
                            odooLastSync: new Date(),
                        },
                    });
                    result.updated++;
                } else {
                    // Create new client
                    await prisma.client.create({
                        data: {
                            name: partner.name,
                            email: partner.email || null,
                            phone: partner.phone || null,
                            odooPartnerId: partner.id,
                            odooData: odooData,
                            odooLastSync: new Date(),
                        },
                    });
                    result.created++;
                }
                result.synced++;
            } catch (partnerError: any) {
                result.errors.push(`Partner ${partner.id}: ${partnerError.message}`);
            }
        }

        result.success = true;
        console.log(`[Odoo Sync] Completed: ${result.created} created, ${result.updated} updated`);
    } catch (error: any) {
        result.errors.push(error.message);
        console.error("[Odoo Sync] Failed:", error.message);
    }

    return result;
}

/**
 * Sync a single client to Odoo (create or update partner)
 */
export async function syncClientToOdoo(clientId: string): Promise<{ success: boolean; partnerId?: number; error?: string }> {
    try {
        const client = await prisma.client.findUnique({
            where: { id: clientId },
        });

        if (!client) {
            return { success: false, error: "Client not found" };
        }

        const odoo = new OdooClient();
        await odoo.authenticate();

        const partnerData = {
            name: client.name,
            email: client.email || false,
            phone: client.phone || false,
            customer_rank: 1,
        };

        let partnerId: number;

        if (client.odooPartnerId) {
            // Update existing partner
            await odoo.execute("res.partner", "write", [[client.odooPartnerId], partnerData]);
            partnerId = client.odooPartnerId;
        } else {
            // Create new partner
            partnerId = await odoo.execute("res.partner", "create", [partnerData]) as number;
        }

        // Update local client with Odoo reference
        await prisma.client.update({
            where: { id: clientId },
            data: {
                odooPartnerId: partnerId,
                odooLastSync: new Date(),
            },
        });

        return { success: true, partnerId };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}

/**
 * Get client data merged with costs calculation
 */
export async function getClientWithCosts(clientId: string) {
    const client = await prisma.client.findUnique({
        where: { id: clientId },
        include: {
            vpsList: {
                include: { services: true },
            },
            services: true,
            payments: {
                orderBy: { date: "desc" },
                take: 10,
            },
        },
    });

    if (!client) return null;

    // Calculate total monthly cost
    const vpsCosts = client.vpsList.reduce((sum: number, vps: VPS) => sum + (vps.monthlyCost || 0), 0);
    const serviceCosts = client.services.reduce((sum: number, service: Service) => sum + (service.monthlyCost || 0), 0);
    const totalMonthlyCost = vpsCosts + serviceCosts + (client.monthlyFee || 0);

    return {
        ...client,
        calculatedMonthlyCost: totalMonthlyCost,
        vpsCosts,
        serviceCosts,
    };
}

/**
 * Background sync - call periodically
 */
let lastSyncTime = 0;
const SYNC_INTERVAL = 5 * 60 * 1000; // 5 minutes

export async function backgroundSync(): Promise<void> {
    const now = Date.now();
    if (now - lastSyncTime < SYNC_INTERVAL) {
        return; // Skip if synced recently
    }

    lastSyncTime = now;
    console.log("[Odoo Sync] Running background sync...");
    await syncOdooPartners();
}

/**
 * Validation Schemas using Zod
 * Provides type-safe validation for all API inputs
 */

import { z } from "zod";

// Client validation schemas
export const ClientCreateSchema = z.object({
    name: z.string().min(2, "Name must be at least 2 characters"),
    email: z.string().email("Invalid email format").optional().nullable(),
    phone: z.string().min(7, "Phone must be at least 7 characters").optional().nullable(),
    companyName: z.string().optional().nullable(),
    notes: z.string().optional().nullable(),
    monthlyFee: z.number().min(0, "Monthly fee cannot be negative").optional(),
    currency: z.enum(["USD", "EUR", "DOP"]).optional(),
    paymentDay: z.number().min(1).max(31).optional(),
});

export const ClientUpdateSchema = ClientCreateSchema.partial();

// VPS validation schemas
export const VPSCreateSchema = z.object({
    name: z.string().min(1, "Name is required"),
    ipAddress: z.string().regex(/^(?:\d{1,3}\.){3}\d{1,3}$/, "Invalid IP address"),
    provider: z.string().optional(),
    hostingerId: z.string().optional().nullable(),
    sshUser: z.string().optional(),
    sshPort: z.number().min(1).max(65535).optional(),
    clientId: z.string().optional().nullable(),
});

// Service validation schemas
export const ServiceCreateSchema = z.object({
    name: z.string().min(1, "Service name is required"),
    type: z.enum(["odoo", "postgres", "nginx", "redis", "other"]),
    port: z.number().min(1).max(65535).optional().nullable(),
    url: z.string().url("Invalid URL").optional().nullable(),
    configFile: z.string().optional().nullable(),
    vpsId: z.string().optional().nullable(),
});

// Payment validation schemas
export const PaymentCreateSchema = z.object({
    amount: z.number().positive("Amount must be positive"),
    currency: z.enum(["USD", "EUR", "DOP"]).optional(),
    clientId: z.string().min(1, "Client ID is required"),
    notes: z.string().optional().nullable(),
    status: z.enum(["pending", "completed", "failed"]).optional(),
});

// Odoo Invoice validation
export const OdooInvoiceCreateSchema = z.object({
    clientId: z.string().optional(),
    partnerId: z.number().optional(),
    lines: z.array(z.object({
        name: z.string().min(1, "Line item name is required"),
        quantity: z.number().positive("Quantity must be positive"),
        price_unit: z.number().min(0, "Price cannot be negative"),
    })).min(1, "At least one invoice line is required"),
});

// Utility function to validate request body
export async function validateRequest<T>(
    request: Request,
    schema: z.ZodSchema<T>
): Promise<{ success: true; data: T } | { success: false; errors: string[] }> {
    try {
        const body = await request.json();
        const result = schema.safeParse(body);

        if (!result.success) {
            const errors = result.error.issues.map((e) => `${e.path.join(".")}: ${e.message}`);
            return { success: false, errors };
        }

        return { success: true, data: result.data };
    } catch (error) {
        return { success: false, errors: ["Invalid JSON body"] };
    }
}

export type ClientCreate = z.infer<typeof ClientCreateSchema>;
export type ClientUpdate = z.infer<typeof ClientUpdateSchema>;
export type VPSCreate = z.infer<typeof VPSCreateSchema>;
export type ServiceCreate = z.infer<typeof ServiceCreateSchema>;
export type PaymentCreate = z.infer<typeof PaymentCreateSchema>;
export type OdooInvoiceCreate = z.infer<typeof OdooInvoiceCreateSchema>;
